/* ══════════════════════════════════════════════════════════════
   app.js — Las eras de Japón y el manga
   Biblioteca Campus del Obelisco · Aula de Cómic · ULPGC
   Versión: 7.8 — Cierre 80%+: 265 títulos cubiertos (95%), quiz+ficha paridad
   
   Depende de: datos.js (CATALOGO, USO_COLORES)
════════════════════════════════════════════════════════════════ */

'use strict';

/* ══════════════════════════════════════════════════════════════════
   SafeStorage — Adaptador robusto para localStorage
   v1.0 · El manga como recurso didáctico · ULPGC

   Problema resuelto:
     localStorage lanza SecurityError en modo privado de Safari/iOS
     y en algunos contextos de iframe. Sin este adaptador, el módulo
     de notas, quiz, estadísticas y expo fallan silenciosamente y
     el docente pierde datos sin advertencia.

   Estrategia:
     1. Detecta disponibilidad real de localStorage en tiempo de carga.
     2. Si no está disponible, usa un Map en memoria como fallback.
     3. Todas las operaciones son seguras (nunca lanzan excepciones).
     4. Avisa al usuario UNA SOLA VEZ mediante un banner no intrusivo.

   API pública (espejo de localStorage + helpers JSON):
     SafeStorage.getItem(key)              → string | null
     SafeStorage.setItem(key, value)       → void
     SafeStorage.removeItem(key)           → void
     SafeStorage.getJSON(key, defaultVal)  → objeto parseado | defaultVal
     SafeStorage.setJSON(key, value)       → void
     SafeStorage.keys()                    → string[]   (todas las claves)
     SafeStorage.clear()                   → void
     SafeStorage.isAvailable              → boolean
══════════════════════════════════════════════════════════════════ */
const SafeStorage = (() => {
  /** @type {boolean} Indica si localStorage está operativo en este contexto */
  let _available = false;

  /** @type {Map<string,string>} Caché en memoria cuando localStorage no está disponible */
  const _memStore = new Map();

  /** @returns {boolean} true si localStorage acepta escritura real */
  function _detectAvailability() {
    const probe = '__manga_ls_probe__';
    try {
      localStorage.setItem(probe, '1');
      localStorage.removeItem(probe);
      return true;
    } catch {
      return false;
    }
  }

  /** Muestra banner de advertencia una sola vez si el almacenamiento es volátil */
  function _warnIfUnavailable() {
    if (_available) return;
    // Evitar banners duplicados (p.ej. si SafeStorage se inicializa varias veces)
    if (document.getElementById('safestorage-warn')) return;

    const banner = document.createElement('div');
    banner.id = 'safestorage-warn';
    Object.assign(banner.style, {
      position: 'fixed', bottom: '0', left: '0', right: '0',
      background: '#7a3a00', color: '#fff',
      padding: '.6rem 1.2rem', fontSize: '.82rem',
      zIndex: '99999', display: 'flex',
      justifyContent: 'space-between', alignItems: 'center',
      fontFamily: 'sans-serif', lineHeight: '1.4'
    });
    banner.setAttribute('role', 'alert');
    banner.setAttribute('aria-live', 'polite');
    banner.innerHTML =
      '<span>⚠️ Este navegador no permite guardar datos (modo privado o restricciones de seguridad). ' +
      'Las notas, quiz y estadísticas se perderán al cerrar la pestaña.</span>' +
      '<button onclick="this.parentElement.remove()" style="background:none;border:none;' +
      'color:#fff;font-size:1.1rem;cursor:pointer;padding:.2rem .6rem;" ' +
      'aria-label="Cerrar aviso">✕</button>';

    // Esperar al DOM antes de insertar
    if (document.body) {
      document.body.appendChild(banner);
    } else {
      document.addEventListener('DOMContentLoaded', () => document.body.appendChild(banner));
    }
  }

  // ── Inicialización en tiempo de carga ──────────────────────────
  _available = _detectAvailability();
  if (!_available) _warnIfUnavailable();

  // ── Implementación interna ─────────────────────────────────────

  /**
   * Obtiene un valor por clave.
   * @param {string} key
   * @returns {string|null}
   */
  function getItem(key) {
    if (_available) {
      try { return localStorage.getItem(key); } catch { /* fallthrough */ }
    }
    return _memStore.has(key) ? _memStore.get(key) : null;
  }

  /**
   * Guarda un valor string.
   * @param {string} key
   * @param {string} value
   */
  function setItem(key, value) {
    if (_available) {
      try {
        localStorage.setItem(key, value);
        return;
      } catch {
        // localStorage lleno (QuotaExceededError) → caer a memoria
      }
    }
    _memStore.set(key, value);
  }

  /**
   * Elimina una clave.
   * @param {string} key
   */
  function removeItem(key) {
    if (_available) {
      try { localStorage.removeItem(key); } catch { /* ignorar */ }
    }
    _memStore.delete(key);
  }

  /**
   * Obtiene y parsea un valor JSON.
   * @param {string} key
   * @param {*} defaultValue - Valor devuelto si la clave no existe o el JSON es inválido
   * @returns {*}
   */
  function getJSON(key, defaultValue) {
    const raw = getItem(key);
    if (raw === null || raw === undefined) return defaultValue;
    try {
      return JSON.parse(raw);
    } catch {
      return defaultValue;
    }
  }

  /**
   * Serializa un valor a JSON y lo guarda.
   * @param {string} key
   * @param {*} value
   */
  function setJSON(key, value) {
    try {
      setItem(key, JSON.stringify(value));
    } catch {
      // JSON.stringify puede fallar con referencias circulares
    }
  }

  /**
   * Devuelve todas las claves almacenadas (localStorage + fallback en memoria).
   * @returns {string[]}
   */
  function keys() {
    if (_available) {
      try {
        return Object.keys(localStorage);
      } catch { /* fallthrough */ }
    }
    return Array.from(_memStore.keys());
  }

  /**
   * Limpia todo el almacenamiento (sólo las claves del propio origen).
   */
  function clear() {
    if (_available) {
      try { localStorage.clear(); } catch { /* ignorar */ }
    }
    _memStore.clear();
  }

  // ── API pública ────────────────────────────────────────────────
  return Object.freeze({
    get isAvailable() { return _available; },
    getItem,
    setItem,
    removeItem,
    getJSON,
    setJSON,
    keys,
    clear,
  });
})();

/* ══════════════════════════════════════════════════════════════════
   Logger — Sistema de logging condicional
   v1.0 · El manga como recurso didáctico · ULPGC

   Problema resuelto:
     console.log dispersos en producción exponen información interna
     a cualquier usuario que abra DevTools. Tampoco permiten filtrar
     por módulo ni por nivel de severidad.

   Estrategia:
     · DEBUG = false en producción → silencio total salvo errores críticos.
     · DEBUG = true en desarrollo  → mensajes completos con timestamp,
       módulo y nivel coloreado en la consola.
     · Logger.error() imprime siempre (incluso en producción) porque
       los errores críticos deben ser visibles para soporte técnico.
     · Activación temporal sin redeployment: escribir en DevTools →
         localStorage.setItem('manga_debug', '1')
       y recargar la página. Para desactivar: removeItem y recargar.

   API pública:
     Logger.debug(module, ...args)   → solo si DEBUG activo
     Logger.warn(module, ...args)    → solo si DEBUG activo
     Logger.error(module, ...args)   → siempre (nivel crítico)
     Logger.group(label, fn)         → agrupa mensajes de debug
     Logger.isDebug                  → boolean getter
══════════════════════════════════════════════════════════════════ */
const Logger = (() => {
  /**
   * Flag de producción.
   * Cambiar a `true` solo durante desarrollo local.
   * Se puede sobreescribir temporalmente vía localStorage:
   *   localStorage.setItem('manga_debug', '1')  → activa debug
   *   localStorage.removeItem('manga_debug')    → vuelve a producción
   * @type {boolean}
   */
  const DEBUG_BUILD = false;

  /** Activación dinámica por localStorage sin recompilar */
  const _debugActive = DEBUG_BUILD ||
    (() => { try { return localStorage.getItem('manga_debug') === '1'; } catch { return false; } })();

  /** Prefijo común para identificar mensajes del recurso en la consola */
  const PREFIX = '[MangaULPGC]';

  /** Estilos CSS para la consola de Chrome/Firefox */
  const STYLES = {
    debug: 'color:#6a9fb5;font-weight:normal',
    warn:  'color:#f0c040;font-weight:bold',
    error: 'color:#e06c75;font-weight:bold',
    module:'color:#98c379;font-style:italic',
  };

  /**
   * Formatea y emite un mensaje de consola.
   * @param {'debug'|'warn'|'error'} level
   * @param {string} module  - Nombre del módulo emisor (ej. 'Quiz', 'IA')
   * @param {any[]} args     - Argumentos adicionales
   */
  function _emit(level, module, ...args) {
    const ts = new Date().toISOString().slice(11, 23); // HH:MM:SS.mmm
    const label = `${PREFIX} %c${level.toUpperCase()}%c [${module}] ${ts}`;

    /* eslint-disable no-console */
    switch (level) {
      case 'debug': console.log(label, STYLES[level], STYLES.module, ...args); break;
      case 'warn':  console.warn(label, STYLES[level], STYLES.module, ...args); break;
      case 'error': console.error(label, STYLES[level], STYLES.module, ...args); break;
    }
    /* eslint-enable no-console */
  }

  // ── API pública ────────────────────────────────────────────────

  /**
   * Mensaje de depuración — solo visible con DEBUG activo.
   * @param {string} module
   * @param {...any} args
   */
  function debug(module, ...args) {
    if (_debugActive) _emit('debug', module, ...args);
  }

  /**
   * Advertencia — solo visible con DEBUG activo.
   * @param {string} module
   * @param {...any} args
   */
  function warn(module, ...args) {
    if (_debugActive) _emit('warn', module, ...args);
  }

  /**
   * Error crítico — siempre visible, incluso en producción.
   * Usar exclusivamente para fallos que impactan la experiencia del usuario.
   * @param {string} module
   * @param {...any} args
   */
  function error(module, ...args) {
    _emit('error', module, ...args);
  }

  /**
   * Agrupa mensajes de debug bajo un mismo título colapsable.
   * No-op si DEBUG no está activo.
   * @param {string} label   - Título del grupo
   * @param {Function} fn    - Función que contiene las llamadas a Logger.*
   */
  function group(label, fn) {
    if (!_debugActive) return;
    /* eslint-disable no-console */
    console.group(`${PREFIX} ${label}`);
    try { fn(); } finally { console.groupEnd(); }
    /* eslint-enable no-console */
  }

  return Object.freeze({
    get isDebug() { return _debugActive; },
    debug,
    warn,
    error,
    group,
  });
})();

/* ══════════════════════════════════════════════════════════════════
   sanitizeHtml — Sanitizador de HTML de fuentes externas
   v1.0 · El manga como recurso didáctico · ULPGC

   Problema resuelto:
     El contenido generado por IA (Claude, Gemini) y los datos de
     tooltips de datos.js se inyectan via innerHTML. Si una respuesta
     de IA incluye etiquetas como <script> o <img onerror=...>,
     el navegador las ejecuta en el contexto de la página.

   Estrategia (sin dependencias externas):
     DOMParser.parseFromString() analiza el HTML en un documento
     inerte (sin ejecutar scripts ni cargar recursos externos).
     Solo se conservan etiquetas del ALLOWLIST. Todo lo demás se
     convierte en texto plano.

   Uso:
     element.innerHTML = sanitizeHtml(untrustedString);

   ALLOWLIST de etiquetas: p, br, strong, em, b, i, ul, ol, li,
     h1-h4, blockquote, code, pre, mark, span, a (href únicamente).

   Nota sobre rendimiento: DOMParser crea un documento completo
   por llamada (≈0.1-0.3 ms en hardware moderno). Aceptable para
   el volumen de este recurso (< 20 llamadas por sesión de usuario).
══════════════════════════════════════════════════════════════════ */

/**
 * Lista blanca de etiquetas HTML permitidas en contenido externo.
 * @type {Set<string>}
 */
const SANITIZE_ALLOWLIST_TAGS = new Set([
  'P', 'BR', 'STRONG', 'EM', 'B', 'I',
  'UL', 'OL', 'LI',
  'H1', 'H2', 'H3', 'H4',
  'BLOCKQUOTE', 'CODE', 'PRE',
  'MARK', 'SPAN',
  'A',
]);

/**
 * Atributos permitidos por etiqueta. El resto se elimina.
 * @type {Object<string, string[]>}
 */
const SANITIZE_ALLOWLIST_ATTRS = {
  A: ['href', 'title'],
  MARK: ['class'],
  SPAN: ['class'],
  CODE: ['class'],
};

/**
 * Sanitiza una cadena HTML de fuente externa.
 * Elimina etiquetas no permitidas (conserva su contenido de texto),
 * elimina atributos no permitidos y bloquea URLs javascript: en href.
 *
 * @param {string} dirtyHtml  - HTML sin confianza (IA, datos externos)
 * @returns {string}          - HTML seguro listo para innerHTML
 */
function sanitizeHtml(dirtyHtml) {
  if (!dirtyHtml || typeof dirtyHtml !== 'string') return '';

  let doc;
  try {
    doc = new DOMParser().parseFromString(dirtyHtml, 'text/html');
  } catch {
    // DOMParser no disponible (entorno muy antiguo): devolver texto plano
    return dirtyHtml.replace(/</g, '&lt;').replace(/>/g, '&gt;');
  }

  /**
   * Limpia recursivamente un nodo y sus descendientes.
   * @param {Node} node
   */
  function _clean(node) {
    const children = Array.from(node.childNodes);
    for (const child of children) {
      if (child.nodeType === Node.TEXT_NODE) continue; // texto: siempre seguro

      if (child.nodeType === Node.ELEMENT_NODE) {
        const tag = child.tagName.toUpperCase();

        if (!SANITIZE_ALLOWLIST_TAGS.has(tag)) {
          // Etiqueta no permitida: conservar texto interior, eliminar etiqueta
          const text = document.createTextNode(child.textContent);
          child.replaceWith(text);
          continue;
        }

        // Limpiar atributos no permitidos
        const allowedAttrs = SANITIZE_ALLOWLIST_ATTRS[tag] || [];
        const attrNames = Array.from(child.attributes).map(a => a.name);
        for (const attr of attrNames) {
          if (!allowedAttrs.includes(attr)) {
            child.removeAttribute(attr);
          }
        }

        // Bloquear hrefs peligrosos (javascript:, data:, vbscript:)
        if (tag === 'A') {
          const href = child.getAttribute('href') || '';
          if (/^(javascript|data|vbscript):/i.test(href.trim())) {
            child.removeAttribute('href');
          }
        }

        _clean(child); // recursivo
      } else {
        // Nodo de otro tipo (comentario, PI…): eliminar
        child.remove();
      }
    }
  }

  _clean(doc.body);
  return doc.body.innerHTML;
}

/**
 * Escapa una cadena para uso seguro como texto plano en innerHTML.
 * Usar cuando el contenido NO debe contener ninguna etiqueta HTML.
 *
 * @param {string} str - Texto sin confianza
 * @returns {string}   - Texto con caracteres HTML escapados
 */
function escapeHtml(str) {
  if (!str || typeof str !== 'string') return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}

/* ══════════════════════════════════════════════════════════════════
   NetworkStatus — Indicador de estado de red para uso en el aula
   v1.0 · El manga como recurso didáctico · ULPGC

   Problema resuelto:
     El Service Worker permite usar el recurso sin conexión, pero el
     docente no sabe si está viendo datos en caché o datos actuales.
     En contextos de aula (WiFi inestable, modo avión) esto genera
     confusión sobre si el IA o las búsquedas funcionarán.

   Comportamiento:
     · Al perder conexión → banner superior azul no intrusivo.
     · Al recuperar conexión → banner verde durante 3 s, luego cierra.
     · En la carga inicial con red → sin banner (caso normal).
     · En la carga inicial sin red → banner inmediato.
     · El docente puede cerrar el banner manualmente en todo momento.
══════════════════════════════════════════════════════════════════ */
const NetworkStatus = (() => {
  const BANNER_ID = 'network-status-banner';

  /** @returns {HTMLElement|null} El banner existente o null */
  function _getBanner() {
    return document.getElementById(BANNER_ID);
  }

  /**
   * Crea e inyecta el banner con el mensaje y estilo dados.
   * @param {'offline'|'online'} type
   */
  function _showBanner(type) {
    _removeBanner();

    const isOffline = type === 'offline';
    const banner = document.createElement('div');
    banner.id = BANNER_ID;
    Object.assign(banner.style, {
      position:   'fixed',
      top:        '0',
      left:       '0',
      right:      '0',
      background: isOffline ? '#1a3a5a' : '#1a4a2a',
      color:      '#fff',
      padding:    '.5rem 1.2rem',
      fontSize:   '.8rem',
      zIndex:     '99998',
      display:    'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      fontFamily: 'sans-serif',
      lineHeight: '1.4',
      boxShadow:  '0 2px 8px rgba(0,0,0,.35)',
      transition: 'opacity .3s',
    });
    banner.setAttribute('role', 'status');
    banner.setAttribute('aria-live', 'polite');

    const msg = isOffline
      ? '📶 Sin conexión — el recurso funciona con datos guardados. El asistente IA no estará disponible.'
      : '✓ Conexión restaurada — todas las funciones están disponibles.';

    banner.innerHTML =
      `<span>${msg}</span>` +
      `<button onclick="document.getElementById('${BANNER_ID}')?.remove()" ` +
      `style="background:none;border:none;color:#fff;font-size:1rem;cursor:pointer;` +
      `padding:.1rem .5rem;opacity:.7;" aria-label="Cerrar aviso">✕</button>`;

    // Esperar al DOM si es necesario
    const _inject = () => document.body.appendChild(banner);
    document.body ? _inject() : document.addEventListener('DOMContentLoaded', _inject);

    // Banner de "conectado" se cierra solo tras 3 s
    if (!isOffline) {
      setTimeout(() => {
        const b = _getBanner();
        if (b) { b.style.opacity = '0'; setTimeout(() => b.remove(), 300); }
      }, 3000);
    }
  }

  /** Elimina el banner si existe */
  function _removeBanner() {
    _getBanner()?.remove();
  }

  // ── Inicialización ─────────────────────────────────────────────
  // Estado inicial: si ya estamos offline al cargar, mostrar inmediatamente
  if (!navigator.onLine) {
    document.addEventListener('DOMContentLoaded', () => {
      _showBanner('offline');
      _syncIaButtons(false);
    });
  }

  // Cambios de estado durante la sesión
  window.addEventListener('offline', () => {
    _showBanner('offline');
    _syncIaButtons(false);
  });
  window.addEventListener('online', () => {
    _showBanner('online');
    _syncIaButtons(true);
  });

  /**
   * Sincroniza el estado enabled/disabled de los botones de envío IA.
   * No desactiva el botón flotante del asistente (el panel puede abrirse
   * para ver el historial de la sesión), pero sí el botón de envío.
   * @param {boolean} online
   */
  /**
   * Sincroniza el estado del asistente según disponibilidad de red.
   * En modo offline: el botón permanece activo (usa consulta local).
   * El placeholder del input cambia para informar al docente.
   * @param {boolean} online
   */
  function _syncIaButtons(online) {
    // El botón de envío NUNCA se deshabilita por falta de red —
    // el modo offline responde con consulta local al catálogo.
    const sendIds = ['asist-send', 'asistSendBtn'];
    sendIds.forEach(id => {
      const btn = document.getElementById(id);
      if (!btn) return;
      btn.disabled = false;
      btn.title    = online ? '' : 'Modo sin conexión — consulta el catálogo local';
    });

    // Actualizar placeholder del input para orientar al docente
    const input = document.getElementById('asistInput');
    if (input) {
      input.placeholder = online
        ? 'Escribe tu consulta…'
        : 'Sin conexión — pregunta por nivel, materia u ODS…';
    }

    // Mostrar/ocultar badge de modo offline en el panel
    const badge = document.getElementById('asist-offline-badge');
    if (badge) badge.style.display = online ? 'none' : 'flex';
  }

  return Object.freeze({ isOnline: () => navigator.onLine });
})();

/* ══════════════════════════════════════════════════════════════════
   FocusTrap — Trampa de foco para modales accesibles
   v1.0 · El manga como recurso didáctico · ULPGC

   Cumple WCAG 2.1:
     · 2.1.1 Keyboard — el foco no escapa del modal por Tab
     · 2.1.2 No Keyboard Trap — Escape libera siempre
     · 2.4.3 Focus Order — el foco vuelve al elemento disparador
     · 2.4.7 Focus Visible — sin cambios (la hoja de estilos ya lo cubre)

   API pública:
     FocusTrap.activate(modalEl, returnEl?)
       · Mueve el foco al primer elemento focusable del modal.
       · Atrapa Tab/Shift+Tab dentro del modal.
       · Escape llama a FocusTrap.deactivate().
       · returnEl: elemento al que devolver el foco al cerrar.
         Si se omite, se usa document.activeElement en el momento
         de llamar a activate().

     FocusTrap.deactivate()
       · Elimina los listeners.
       · Devuelve el foco al elemento disparador original.

   Uso:
     // Al abrir:
     FocusTrap.activate(document.getElementById('miModal'), triggerBtn);
     // Al cerrar:
     FocusTrap.deactivate();
══════════════════════════════════════════════════════════════════ */
const FocusTrap = (() => {
  /** Selectores CSS de elementos nativamente focusables */
  const FOCUSABLE = [
    'a[href]',
    'button:not([disabled])',
    'input:not([disabled]):not([type="hidden"])',
    'select:not([disabled])',
    'textarea:not([disabled])',
    '[tabindex]:not([tabindex="-1"])',
    'details > summary',
  ].join(', ');

  let _container  = null;   // Elemento modal activo
  let _returnEl   = null;   // Elemento al que devolver el foco
  let _handler    = null;   // Listener de teclado activo

  /**
   * Devuelve la lista ordenada de elementos focusables dentro del contenedor.
   * @param {HTMLElement} container
   * @returns {HTMLElement[]}
   */
  function _getFocusables(container) {
    return Array.from(container.querySelectorAll(FOCUSABLE))
      .filter(el => !el.closest('[hidden]') && !el.closest('[aria-hidden="true"]'));
  }

  /**
   * Activa la trampa de foco en el modal dado.
   * @param {HTMLElement} modalEl   - Contenedor del modal
   * @param {HTMLElement} [returnEl] - Elemento al que volver al cerrar
   */
  function activate(modalEl, returnEl) {
    if (!modalEl) return;

    // Limpiar trampa anterior si quedara activa
    deactivate();

    _container = modalEl;
    _returnEl  = returnEl || document.activeElement;

    const focusables = _getFocusables(_container);

    // Mover foco al primer elemento focusable (o al propio modal si no hay)
    if (focusables.length > 0) {
      // Pequeño delay para que la transición CSS del modal termine
      setTimeout(() => focusables[0]?.focus(), 50);
    } else {
      _container.setAttribute('tabindex', '-1');
      setTimeout(() => _container.focus(), 50);
    }

    _handler = function(e) {
      if (e.key === 'Escape') {
        e.preventDefault();
        deactivate();
        return;
      }

      if (e.key !== 'Tab') return;

      const focusables = _getFocusables(_container);
      if (focusables.length === 0) { e.preventDefault(); return; }

      const first = focusables[0];
      const last  = focusables[focusables.length - 1];
      const active = document.activeElement;

      if (e.shiftKey) {
        // Shift+Tab: si estamos en el primero → saltar al último
        if (active === first || !_container.contains(active)) {
          e.preventDefault();
          last.focus();
        }
      } else {
        // Tab: si estamos en el último → saltar al primero
        if (active === last || !_container.contains(active)) {
          e.preventDefault();
          first.focus();
        }
      }
    };

    document.addEventListener('keydown', _handler, true);
    Logger.debug('FocusTrap', 'Activado en', modalEl.id || modalEl.className);
  }

  /**
   * Desactiva la trampa y devuelve el foco al elemento disparador.
   */
  function deactivate() {
    if (_handler) {
      document.removeEventListener('keydown', _handler, true);
      _handler = null;
    }

    // Devolver foco al elemento que disparó el modal
    if (_returnEl && typeof _returnEl.focus === 'function') {
      // Delay mínimo para que el modal termine de cerrarse antes de mover el foco
      setTimeout(() => {
        try { _returnEl.focus(); } catch { /* elemento ya no existe */ }
      }, 60);
    }

    _container = null;
    _returnEl  = null;
    Logger.debug('FocusTrap', 'Desactivado');
  }

  return Object.freeze({ activate, deactivate });
})();

/* ══════════════════════════════════════════════════════════════════
   CatalogoLocal — Capa de edición del catálogo sobre SafeStorage
   v1.0 · El manga como recurso didáctico · ULPGC

   Problema resuelto:
     Añadir o editar títulos en datos.js requiere conocimiento técnico
     y acceso al repositorio. Un bibliotecario no puede registrar hoy
     mismo un manga que acaba de ingresar al fondo.

   Arquitectura (inmutable / mutable):
     · CATALOGO[]            → catálogo base de datos.js (inmutable en runtime)
     · manga_catalogo_local  → entradas añadidas/editadas por el docente (SafeStorage)
     · CATALOGO_EFECTIVO[]   → merge de ambas capas; todo el código usa ésta

   Formato de una entrada local:
     {
       _id:  string único (timestamp + random),
       _op:  'add' | 'edit' | 'delete',
       titulo, autor, uso, nivel, color, tip, periodo,
       badges, niveles, ods, opac, sensitive
     }

   Reglas de merge:
     · 'add'    → se añade al final de CATALOGO_EFECTIVO
     · 'edit'   → sobreescribe la entrada base con el mismo título
     · 'delete' → elimina la entrada base con ese título

   El merge ocurre una vez al cargar el DOM y cada vez que el editor
   guarda un cambio (invalidación + re-render).
══════════════════════════════════════════════════════════════════ */
const CatalogoLocal = (() => {
  const STORE_KEY = 'manga_catalogo_local';

  /** Colores canónicos por uso (consistentes con datos.js) */
  const COLOR_POR_USO = {
    historia:'#5A3A1A', emocional:'#7A5A0A', ciencia:'#1A5A8B',
    filosofia:'#4A2A6A', genero:'#8B1A4A', visual:'#5E3A8A',
    lenguas:'#2E6E3A', inclusion:'#3A4A8A',
  };

  /** @returns {Array} Entradas locales del docente */
  function _getLocal() {
    return SafeStorage.getJSON(STORE_KEY, []);
  }

  /** @param {Array} entries */
  function _saveLocal(entries) {
    SafeStorage.setJSON(STORE_KEY, entries);
  }

  /**
   * Construye el catálogo efectivo: base + entradas locales.
   * @returns {Array} CATALOGO_EFECTIVO
   */
  function buildEffective() {
    if (typeof CATALOGO === 'undefined') return [];
    const base    = [...CATALOGO];
    const local   = _getLocal();
    const result  = [];
    const deleted = new Set(local.filter(e => e._op === 'delete').map(e => e.titulo));
    const edited  = new Map(local.filter(e => e._op === 'edit').map(e => [e.titulo, e]));

    // 1. Recorrer base: filtrar eliminados, aplicar ediciones
    for (const entry of base) {
      if (deleted.has(entry.titulo)) continue;
      result.push(edited.has(entry.titulo) ? { ...entry, ...edited.get(entry.titulo) } : entry);
    }

    // 2. Añadir entradas nuevas
    for (const entry of local.filter(e => e._op === 'add')) {
      result.push(entry);
    }

    return result;
  }

  /**
   * Añade una nueva entrada al catálogo local.
   * @param {Object} data - Campos del formulario
   * @returns {string}    - _id generado
   */
  function addEntry(data) {
    const entries = _getLocal();
    const _id = Date.now() + '_' + Math.random().toString(36).slice(2, 7);
    entries.push({ _id, _op: 'add', ...data });
    _saveLocal(entries);
    return _id;
  }

  /**
   * Edita una entrada existente (base o local).
   * @param {string} titulo  - Título original (clave de búsqueda)
   * @param {Object} data    - Campos actualizados
   */
  function editEntry(titulo, data) {
    const entries = _getLocal();
    const existingIdx = entries.findIndex(e => e.titulo === titulo && e._op !== 'delete');

    if (existingIdx >= 0) {
      // Actualizar entrada local existente
      entries[existingIdx] = { ...entries[existingIdx], ...data, titulo };
    } else {
      // Crear entrada de edición sobre la base
      const _id = Date.now() + '_' + Math.random().toString(36).slice(2, 7);
      entries.push({ _id, _op: 'edit', titulo, ...data });
    }
    _saveLocal(entries);
  }

  /**
   * Marca una entrada como eliminada.
   * @param {string} titulo
   */
  function deleteEntry(titulo) {
    const entries = _getLocal();
    // Si es entrada local de 'add', eliminarla directamente
    const localIdx = entries.findIndex(e => e.titulo === titulo && e._op === 'add');
    if (localIdx >= 0) {
      entries.splice(localIdx, 1);
    } else {
      // Si es entrada base, marcar como 'delete'
      const existing = entries.findIndex(e => e.titulo === titulo && e._op === 'edit');
      if (existing >= 0) entries.splice(existing, 1); // limpiar edición previa
      const _id = Date.now() + '_' + Math.random().toString(36).slice(2, 7);
      entries.push({ _id, _op: 'delete', titulo });
    }
    _saveLocal(entries);
  }

  /**
   * Devuelve estadísticas del catálogo local.
   * @returns {{ adds: number, edits: number, deletes: number }}
   */
  function getStats() {
    const local = _getLocal();
    return {
      adds:    local.filter(e => e._op === 'add').length,
      edits:   local.filter(e => e._op === 'edit').length,
      deletes: local.filter(e => e._op === 'delete').length,
      total:   local.length,
    };
  }

  /**
   * Exporta el catálogo efectivo completo como JSON descargable.
   */
  function exportJSON() {
    const effective = buildEffective();
    const payload   = {
      meta: {
        generado: new Date().toISOString(),
        version: '1.0',
        total: effective.length,
        nota: 'Catálogo efectivo = base (datos.js) + ediciones locales del docente.',
      },
      catalogo: effective,
    };
    _descargarBlob(
      new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' }),
      `manga-catalogo-${new Date().toISOString().slice(0,10)}.json`
    );
  }

  /**
   * Exporta las entradas locales como CSV (para revisión en Excel).
   */
  function exportCSV() {
    const local = _getLocal();
    if (!local.length) { alert('No hay entradas locales que exportar.'); return; }

    const SEP  = ';';
    const CRLF = '\r\n';
    const esc  = v => { const s = String(v??'').replace(/"/g,'""'); return s.includes(SEP)||s.includes('\n')||s.includes('"') ? `"${s}"` : s; };

    const header = ['_op','titulo','autor','uso','nivel','tip','periodo','badges','ods','opac','sensitive'].join(SEP);
    const rows   = local.map(e => [
      e._op, e.titulo, e.autor, e.uso, e.nivel, e.tip, e.periodo,
      (e.badges||[]).join('|'), (e.ods||[]).join('|'), e.opac,
      e.sensitive ? '1' : '0',
    ].map(esc).join(SEP));

    _descargarBlob(
      new Blob(['\uFEFF' + [header, ...rows].join(CRLF)], { type: 'text/csv;charset=utf-8' }),
      `manga-catalogo-local-${new Date().toISOString().slice(0,10)}.csv`
    );
  }

  /**
   * Importa entradas desde un JSON exportado por exportJSON() o exportCSV().
   * Acepta dos formatos:
   *   · { meta, catalogo: [...] }     → catálogo efectivo completo
   *   · [{ _op, titulo, ... }, ...]   → entradas locales directas
   *
   * @param {string} jsonText  - Contenido del archivo JSON como string
   * @param {'merge'|'replace'} mode
   *   · 'merge'   → añade/actualiza sin borrar lo ya existente
   *   · 'replace' → descarta todo lo local y reemplaza con el importado
   * @returns {{ ok: number, skipped: number, errors: string[] }}
   */
  function importJSON(jsonText, mode = 'merge') {
    let parsed;
    try {
      parsed = JSON.parse(jsonText);
    } catch {
      return { ok: 0, skipped: 0, errors: ['El archivo no es JSON válido.'] };
    }

    // Normalizar: detectar formato (catálogo completo vs entradas locales)
    let entries = [];
    if (Array.isArray(parsed)) {
      // Formato: array de entradas locales [ { _op, titulo, ... } ]
      entries = parsed;
    } else if (parsed?.catalogo && Array.isArray(parsed.catalogo)) {
      // Formato: { meta, catalogo: [...] } — convertir a entradas de tipo 'add'
      const baseSet = new Set((typeof CATALOGO !== 'undefined' ? CATALOGO : []).map(t => t.titulo));
      entries = parsed.catalogo
        .filter(t => t.titulo)
        .map(t => ({
          _id:  Date.now() + '_' + Math.random().toString(36).slice(2, 7),
          _op:  baseSet.has(t.titulo) ? 'edit' : 'add',
          ...t,
        }));
    } else {
      return { ok: 0, skipped: 0, errors: ['Formato JSON no reconocido. Usa un archivo exportado por esta aplicación.'] };
    }

    let ok = 0, skipped = 0;
    const errors = [];
    const current = mode === 'replace' ? [] : _getLocal();
    const currentTitles = new Map(current.map(e => [e.titulo, e]));

    for (const e of entries) {
      if (!e.titulo || typeof e.titulo !== 'string') { skipped++; continue; }
      if (!['add','edit','delete'].includes(e._op)) { e._op = 'add'; }

      // En modo merge: no sobreescribir si ya existe con misma operación
      if (mode === 'merge' && currentTitles.has(e.titulo)) {
        // Actualizar la entrada existente
        const idx = current.findIndex(x => x.titulo === e.titulo);
        if (idx >= 0) current[idx] = { ...current[idx], ...e };
      } else {
        e._id = e._id || (Date.now() + '_' + Math.random().toString(36).slice(2, 7));
        current.push(e);
        currentTitles.set(e.titulo, e);
      }
      ok++;
    }

    _saveLocal(current);
    return { ok, skipped, errors };
  }

  /**
   * Importa entradas desde un CSV exportado por exportCSV() o preparado manualmente.
   * Columnas esperadas (separador ';' con BOM opcional):
   *   _op; titulo; autor; uso; nivel; tip; periodo; badges; ods; opac; sensitive
   *   · badges: separados por '|'
   *   · ods:    separados por '|'
   *   · sensitive: '1' / '0'
   *
   * @param {string} csvText
   * @param {'merge'|'replace'} mode
   * @returns {{ ok: number, skipped: number, errors: string[] }}
   */
  function importCSV(csvText, mode = 'merge') {
    // Eliminar BOM UTF-8 si existe
    const text  = csvText.replace(/^\uFEFF/, '').trim();
    const lines = text.split(/\r?\n/).filter(l => l.trim());
    if (lines.length < 2) return { ok: 0, skipped: 0, errors: ['El CSV está vacío o solo tiene cabecera.'] };

    const SEP = ';';

    /**
     * Parsea una línea CSV respetando campos entre comillas.
     * @param {string} line
     * @returns {string[]}
     */
    function parseLine(line) {
      const result = [];
      let cur = '', inQ = false;
      for (let i = 0; i < line.length; i++) {
        const ch = line[i];
        if (inQ) {
          if (ch === '"' && line[i+1] === '"') { cur += '"'; i++; }
          else if (ch === '"') { inQ = false; }
          else { cur += ch; }
        } else {
          if (ch === '"') { inQ = true; }
          else if (ch === SEP) { result.push(cur); cur = ''; }
          else { cur += ch; }
        }
      }
      result.push(cur);
      return result;
    }

    const headers = parseLine(lines[0]).map(h => h.trim().replace(/^"(.*)"$/, '$1'));
    const colIdx  = {};
    headers.forEach((h, i) => { colIdx[h] = i; });

    const required = ['titulo'];
    const missing  = required.filter(f => colIdx[f] === undefined);
    if (missing.length) {
      return { ok: 0, skipped: 0, errors: [`Columna obligatoria no encontrada: ${missing.join(', ')}. La cabecera debe incluir: _op;titulo;autor;uso;nivel;tip;periodo;badges;ods;opac;sensitive`] };
    }

    const get = (row, field) => (row[colIdx[field]] ?? '').trim();

    let ok = 0, skipped = 0;
    const errors = [];
    const entries = [];

    for (let i = 1; i < lines.length; i++) {
      const row = parseLine(lines[i]);
      const titulo = get(row, 'titulo');
      if (!titulo) { skipped++; continue; }

      const _op    = ['add','edit','delete'].includes(get(row,'_op')) ? get(row,'_op') : 'add';
      const badges = get(row,'badges') ? get(row,'badges').split('|').map(b => b.trim()).filter(Boolean) : [];
      const odsRaw = get(row,'ods') ? get(row,'ods').split('|').map(n => parseInt(n.trim(), 10)).filter(n => !isNaN(n)) : [];

      entries.push({
        _id:       Date.now() + '_' + Math.random().toString(36).slice(2, 7) + '_' + i,
        _op,
        titulo,
        autor:     get(row,'autor')   || '',
        uso:       get(row,'uso')     || 'historia',
        nivel:     get(row,'nivel')   || 'secundaria',
        color:     COLOR_POR_USO[get(row,'uso')?.split(' ')[0]] || '#5A3A1A',
        tip:       get(row,'tip')     || '',
        periodo:   get(row,'periodo') || '',
        badges,
        niveles:   (get(row,'nivel')||'secundaria').split(' ').map(n => ({ infantil:'Infantil', primaria:'Primaria', secundaria:'Secundaria', bachillerato:'Bachillerato', universidad:'Universidad' }[n] || n)),
        ods:       odsRaw,
        opac:      get(row,'opac')    || '',
        sensitive: get(row,'sensitive') === '1',
      });
      ok++;
    }

    if (!entries.length) return { ok: 0, skipped, errors };

    // Aplicar al almacenamiento local
    const current = mode === 'replace' ? [] : _getLocal();
    if (mode === 'replace') {
      _saveLocal(entries);
    } else {
      const currentTitles = new Map(current.map(e => [e.titulo, e]));
      for (const e of entries) {
        const idx = current.findIndex(x => x.titulo === e.titulo);
        if (idx >= 0) current[idx] = { ...current[idx], ...e };
        else current.push(e);
      }
      _saveLocal(current);
    }

    return { ok, skipped, errors };
  }

  /**
   * Descarta todas las modificaciones locales.
   */
  function resetLocal() {
    SafeStorage.removeItem(STORE_KEY);
  }

  return Object.freeze({
    COLOR_POR_USO,
    buildEffective,
    addEntry,
    editEntry,
    deleteEntry,
    getStats,
    exportJSON,
    exportCSV,
    importJSON,
    importCSV,
    resetLocal,
  });
})();

/* ── Inicialización del catálogo efectivo ────────────────────────
   CATALOGO_EFECTIVO reemplaza a CATALOGO en todo el código de app.js.
   Se reconstruye llamando a _refreshCatalogoEfectivo() tras cada
   edición para que renderCatalog() muestre los cambios al instante. */
let CATALOGO_EFECTIVO = [];

function _refreshCatalogoEfectivo() {
  CATALOGO_EFECTIVO = CatalogoLocal.buildEffective();
  // Actualizar la referencia global que usa renderCatalog y el resto
  // redirigiendo CATALOGO a CATALOGO_EFECTIVO (sin modificar datos.js)
  if (typeof CATALOGO !== 'undefined') {
    CATALOGO_EFECTIVO.__proto__ = CATALOGO.__proto__; // misma interfaz de Array
  }
  Logger.debug('CatalogoLocal', `Catálogo efectivo: ${CATALOGO_EFECTIVO.length} títulos`);
}

// ── CONSTANTE GLOBAL DE CLAVE API ────────────────────────────────
// Usada en ambos IIFEs del asistente (líneas ~1861 y ~4360).
// Si se renombra, cambiar en los dos sitios.
const MANGA_ASIST_KEY = 'manga_asist_apikey';

// ══════════════════════════════════════════════════════════════════
// MOTOR IA DUAL — Claude (artifact) + Gemini (standalone, con clave)
//
// Arquitectura de prioridad:
//   1.º Gemini Flash   — activo si el docente aporta clave de Google AI Studio.
//   2.º Claude Sonnet  — activo en despliegue como artifact de claude.ai
//       (el proxy de Anthropic inyecta la clave automáticamente).
//       En servidor autónomo (ULPGC), Claude requiere clave propia → usa Gemini.
//
// Transparencia EU AI Act Art. 13 & 50: todo contenido generado lleva
// badge visible con el proveedor real utilizado en cada respuesta.
// ══════════════════════════════════════════════════════════════════

/** Proveedor activo en la última llamada. Usado por los badges de transparencia. */
let _lastAiProvider = 'Claude';

/**
 * Llama a la API de Anthropic Claude Sonnet.
 * No requiere API key del usuario — disponible sin configuración.
 *
 * @param {string} promptText - Contenido del prompt
 * @returns {Promise<string>} - Texto de respuesta del modelo
 * @throws {Error}            - Si la API no responde o devuelve error
 */
async function claudeRequest(promptText) {
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 1000,
      messages: [{ role: 'user', content: promptText }]
    })
  });

  if (!resp.ok) {
    const err = await resp.json().catch(() => ({}));
    throw new Error(err?.error?.message || `Error Claude HTTP ${resp.status}`);
  }

  const data = await resp.json();
  const text = (data.content || [])
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('');

  if (!text) throw new Error('Claude devolvió una respuesta vacía.');
  _lastAiProvider = 'Claude';
  return text;
}

/**
 * Enrutador IA: usa Gemini si hay clave válida disponible; Claude en caso contrario.
 * Si Gemini falla con la clave provista, retrocede a Claude como respaldo silencioso.
 *
 * @param {string} promptText   - Contenido del prompt
 * @param {string} [geminiKey]  - Clave de Google AI Studio (opcional)
 * @returns {Promise<string>}   - Texto de respuesta del proveedor activo
 */
async function aiRequest(promptText, geminiKey) {
  if (geminiKey && geminiKey.startsWith('AIza')) {
    try {
      const result = await geminiRequest(geminiKey, promptText);
      _lastAiProvider = 'Gemini';
      return result;
    } catch (e) {
      // Fallback silencioso a Claude si Gemini falla
      _lastAiProvider = 'Claude';
    }
  }
  return claudeRequest(promptText);
}

// ── BOTÓN VOLVER ARRIBA ──────────────────────────────────────
document.addEventListener('DOMContentLoaded', function() {
  const btn = document.getElementById('gtt-btn');
  if (!btn) return;
  btn.classList.add('visible');
  btn.addEventListener('click', () => {
    const anchor = document.getElementById('top-anchor');
    if (anchor) anchor.scrollIntoView({ behavior: 'smooth', block: 'start' });
    try { window.scrollTo({ top: 0, behavior: 'smooth' }); } catch(e) {}
    try { document.documentElement.scrollTop = 0; } catch(e) {}
    try { document.body.scrollTop = 0; } catch(e) {}
  });
});

// ── Modo proyección ──────────────────────────────────────────────
let modoProyeccionActive = false;

function toggleProyeccion() {
  modoProyeccionActive = !modoProyeccionActive;
  document.body.classList.toggle('modo-proyeccion', modoProyeccionActive);

  if (modoProyeccionActive) {
    // Scroll to timeline
    const sc = document.getElementById('sc');
    if (sc) sc.scrollIntoView({ behavior: 'smooth' });
    // Show exit button
    document.querySelector('.proyeccion-exit').style.display = 'flex';
    // Announce
    document.title = '[ PROYECCIÓN ] Las eras de Japón y el manga — Recurso didáctico · Biblioteca ULPGC';
    // Try fullscreen
    if (document.documentElement.requestFullscreen) {
      document.documentElement.requestFullscreen().catch(() => {});
    }
  } else {
    document.querySelector('.proyeccion-exit').style.display = 'none';
    document.title = 'Las eras de Japón y el manga — Recurso didáctico · Biblioteca ULPGC';
    if (document.fullscreenElement && document.exitFullscreen) {
      document.exitFullscreen().catch(() => {});
    }
  }
}

// Exit on Escape key
document.addEventListener('keydown', e => {
  if (e.key === 'Escape' && modoProyeccionActive) {
    toggleProyeccion();
  }
});

// Sync state if browser exits fullscreen via its own UI (F11, Escape, etc.)
document.addEventListener('fullscreenchange', () => {
  if (!document.fullscreenElement && modoProyeccionActive) {
    modoProyeccionActive = false;
    document.body.classList.remove('modo-proyeccion');
    const exitBtn = document.querySelector('.proyeccion-exit');
    if (exitBtn) exitBtn.style.display = 'none';
    document.title = 'Las eras de Japón y el manga — Recurso didáctico · Biblioteca ULPGC';
    // Also exit discovery if active
    if (modoDescubrimientoActive) exitEraDiscovery(true);
  }
});

// ── MODO DESCUBRIMIENTO ERA POR ERA ─────────────────────────────
let modoDescubrimientoActive = false;
let eraColumns = [];
let eraIndex   = 0;

function getEraColumns() {
  return Array.from(document.querySelectorAll('#tl .col'));
}

function toggleEraDiscovery() {
  if (!modoDescubrimientoActive) {
    // Activar modo proyección si no está activo
    if (!modoProyeccionActive) toggleProyeccion();
    startEraDiscovery();
  } else {
    exitEraDiscovery();
  }
}

function startEraDiscovery() {
  eraColumns = getEraColumns();
  if (!eraColumns.length) return;
  modoDescubrimientoActive = true;
  eraIndex = 0;
  document.body.classList.add('modo-descubrimiento');
  // Show/hide FAB button
  const btn = document.getElementById('eraDiscBtn');
  if (btn) btn.textContent = '⊟';
  showEra(0);
}

function exitEraDiscovery(silent) {
  modoDescubrimientoActive = false;
  document.body.classList.remove('modo-descubrimiento');
  // Remove active class from all
  eraColumns.forEach(c => c.classList.remove('era-active'));
  const btn = document.getElementById('eraDiscBtn');
  if (btn) btn.textContent = '▶';
  updateEraDiscBar();
}

function showEra(idx) {
  eraColumns = getEraColumns();
  if (!eraColumns.length) return;
  idx = Math.max(0, Math.min(idx, eraColumns.length - 1));
  eraIndex = idx;

  // Swap active class
  eraColumns.forEach((c, i) => {
    c.classList.toggle('era-active', i === idx);
  });

  // Update nav bar info
  const col      = eraColumns[idx];
  const nameEl   = col.querySelector('.era-name');
  const jpEl     = col.querySelector('.era-jp');
  const datesEl  = col.querySelector('.era-dates');
  document.getElementById('eraDiscCounter').textContent = `${idx + 1} / ${eraColumns.length}`;
  document.getElementById('eraDiscName').textContent    = nameEl?.textContent  || '';
  document.getElementById('eraDiscJp').textContent      = jpEl?.textContent    || '';
  document.getElementById('eraDiscDates').textContent   = datesEl?.textContent || '';

  // Disable/enable prev-next
  document.getElementById('eraDiscPrev').disabled = idx === 0;
  document.getElementById('eraDiscNext').disabled = idx === eraColumns.length - 1;

  updateEraDiscBar();
}

function eraNav(dir) {
  if (!modoDescubrimientoActive) return;
  showEra(eraIndex + dir);
}

function updateEraDiscBar() {
  // The bar visibility is controlled by CSS body class,
  // but keep prev/next state consistent
}

// Keyboard navigation in discovery mode
document.addEventListener('keydown', function(e) {
  if (!modoDescubrimientoActive) return;
  if (e.key === 'ArrowRight' || e.key === ' ') {
    e.preventDefault();
    eraNav(1);
  } else if (e.key === 'ArrowLeft') {
    e.preventDefault();
    eraNav(-1);
  } else if (e.key === 'Escape') {
    exitEraDiscovery();
  }
});

// Show era-by-era button only when projection mode is active
const _origToggleProyeccion = toggleProyeccion;
toggleProyeccion = function() {
  _origToggleProyeccion();
  const btn = document.getElementById('eraDiscBtn');
  if (btn) btn.style.display = modoProyeccionActive ? 'flex' : 'none';
  // If exiting projection, also exit discovery
  if (!modoProyeccionActive && modoDescubrimientoActive) {
    exitEraDiscovery(true);
  }
};


// ══════════════════════════════════════════════════════════════════
// ══════════════════════════════════════════════════════════════════
// CONTADOR DE VISITAS Y ESTADÍSTICAS DE USO — localStorage
// ══════════════════════════════════════════════════════════════════
(function() {
  const STATS_KEY = 'manga_stats_v4';

  function getStats() {
    return SafeStorage.getJSON(STATS_KEY, {});
  }
  function saveStats(s) {
    SafeStorage.setJSON(STATS_KEY, s);
  }

  // ── API pública para trackear eventos ─────────────────────────
  window._trackStat = function(key) {
    const s = getStats();
    s[key] = (s[key] || 0) + 1;
    saveStats(s);
  };

  // ── Contar visita al cargar ───────────────────────────────────
  document.addEventListener('DOMContentLoaded', function() {
    window._trackStat('visitas');
    const s = getStats();

    // Mostrar visitas en el header — solo cuando el dato existe (M-03).
    const el = document.getElementById('visitCountGlobal');
    const wrap = document.querySelector('.visit-counter-portada');
    const v = s.visitas;
    if (el && typeof v === 'number' && v > 0) {
      el.textContent = v.toLocaleString('es-ES');
      if (wrap) wrap.removeAttribute('hidden');
    } else if (wrap) {
      wrap.setAttribute('hidden', '');
    }

    // Parchear funciones principales para registrar uso
    setTimeout(() => {
      [
        ['openFicha',        'fichas_abiertas'],
        ['openRubrica',      'rubricas_abiertas'],
        ['openLectura',      'lecturas_abiertas'],
        ['openExpres',       'expres_abiertas'],
        ['generarSecuencia', 'secuencias_generadas'],
        ['generarRubrica',   'rubricas_generadas'],
      ].forEach(([fn, stat]) => {
        const orig = window[fn];
        if (typeof orig === 'function' && !orig._tracked) {
          window[fn] = function(...args) {
            window._trackStat(stat);
            return orig.apply(this, args);
          };
          window[fn]._tracked = true;
        }
      });
    }, 600);
  });

  // ── Panel de estadísticas ─────────────────────────────────────
  window.showStats = function() { openPanelDocente('stats'); };
})();

/* ══════════════════════════════════════════════════════════════════
   Panel docente unificado — openPanelDocente()
   v1.0 · El manga como recurso didáctico · ULPGC

   Reúne en un único modal con cuatro pestañas los datos del docente
   que anteriormente vivían en cuatro paneles separados:
     · Estadísticas de uso (contadores acumulados)
     · Notas de ficha (observaciones, valoraciones por título)
     · Historial (sesión actual + visitas anteriores)
     · Exportar (JSON + CSV)

   Acceso: FAB → icono docente, o llamada directa desde showStats().
   Compatible con FocusTrap y dark mode.
══════════════════════════════════════════════════════════════════ */

/**
 * Abre el panel docente unificado en la pestaña indicada.
 * @param {'stats'|'notas'|'historial'|'exportar'} [tab='stats']
 */
function openPanelDocente(tab = 'stats') {
  const _opener = document.activeElement;

  let overlay = document.getElementById('panelDocenteOverlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'panelDocenteOverlay';
    overlay.setAttribute('role', 'dialog');
    overlay.setAttribute('aria-modal', 'true');
    overlay.setAttribute('aria-labelledby', 'panelDocenteTitle');
    overlay.className = 'panel-docente-overlay';
    document.body.appendChild(overlay);
    overlay.addEventListener('click', e => {
      if (e.target === overlay) closePanelDocente();
    });
  }

  overlay.innerHTML = `
    <div class="panel-docente-modal" id="panelDocenteModal">
      <div class="panel-docente-header">
        <span id="panelDocenteTitle" class="panel-docente-title">Panel docente</span>
        <button type="button" class="panel-docente-close" data-action="closePanelDocente"
                aria-label="Cerrar panel">✕</button>
      </div>

      <nav class="panel-docente-tabs" role="tablist" aria-label="Secciones del panel docente">
        ${[
          { id:'stats',    icon:'📊', label:'Estadísticas' },
          { id:'notas',    icon:'✎',  label:'Notas'        },
          { id:'historial',icon:'⧖',  label:'Historial'    },
          { id:'exportar', icon:'⬇',  label:'Exportar'     },
          { id:'catalogo', icon:'✚',  label:'Catálogo'     },
        ].map(t => `
          <button type="button"
                  role="tab"
                  id="pd-tab-${t.id}"
                  aria-controls="pd-panel-${t.id}"
                  aria-selected="${t.id === tab ? 'true' : 'false'}"
                  class="pd-tab${t.id === tab ? ' active' : ''}"
                  data-action="switchPanelDocenteTab" data-arg="${t.id}">
            <span aria-hidden="true">${t.icon}</span> ${t.label}
          </button>`).join('')}
      </nav>

      <div class="panel-docente-body" id="panelDocenteBody"
           role="tabpanel" aria-labelledby="pd-tab-${tab}">
        <!-- Contenido inyectado por _renderPdTab() -->
      </div>
    </div>`;

  overlay.style.display = 'flex';
  document.body.style.overflow = 'hidden';
  FocusTrap.activate(document.getElementById('panelDocenteModal'), _opener);
  _renderPdTab(tab);
}

function closePanelDocente() {
  const overlay = document.getElementById('panelDocenteOverlay');
  if (overlay) overlay.style.display = 'none';
  document.body.style.overflow = '';
  FocusTrap.deactivate();
}

/**
 * Cambia la pestaña activa del panel docente.
 * @param {string} tab
 */
function switchPanelDocenteTab(tab) {
  document.querySelectorAll('.pd-tab').forEach(btn => {
    const isActive = btn.dataset.arg === tab;
    btn.classList.toggle('active', isActive);
    btn.setAttribute('aria-selected', isActive ? 'true' : 'false');
  });
  const body = document.getElementById('panelDocenteBody');
  if (body) body.setAttribute('aria-labelledby', `pd-tab-${tab}`);
  _renderPdTab(tab);
}

/**
 * Renderiza el contenido de la pestaña activa.
 * @param {string} tab
 */
function _renderPdTab(tab) {
  const body = document.getElementById('panelDocenteBody');
  if (!body) return;

  switch (tab) {
    case 'stats':    _pdStats(body);    break;
    case 'notas':    _pdNotas(body);    break;
    case 'historial':_pdHistorial(body);break;
    case 'exportar': _pdExportar(body); break;
    case 'catalogo': _pdCatalogo(body); break;
  }
}

/* ── Pestaña: Catálogo (editor) ──────────────────────────────── */

