// ── Buscador de catálogo ────────────────────────────────────────
function searchCatalog(q) {
  const cards    = document.querySelectorAll('.cat-card');
  const grid     = document.getElementById('catGrid');
  const section  = document.getElementById('catalogo');
  const count    = document.getElementById('searchCount');
  const clearBtn = document.getElementById('searchClear');
  const term     = q.trim().toLowerCase();
  const words    = term ? term.split(/\s+/).filter(Boolean) : [];
  const aulaOn   = document.body.classList.contains('modo-aula');
  const searching = words.length > 0;

  // Toggle search state on section and grid
  section?.classList.toggle('catalog-searching', searching);
  grid?.classList.toggle('search-active', searching);
  if (clearBtn) clearBtn.classList.toggle('visible', searching);

  let visible = 0;
  let firstMatch = null;

  cards.forEach(card => {
    const isSensitive = aulaOn && card.hasAttribute('data-sensitive');

    // Remove injected tip from previous search
    card.querySelector('.cat-search-tip')?.remove();
    card.classList.remove('search-match', 'search-hidden');
    _restoreText(card);

    if (isSensitive) return;
    if (!searching) return;

    const titleEl  = card.querySelector('.cat-title');
    const authorEl = card.querySelector('.cat-author');
    const tip      = card.getAttribute('data-tip') || '';
    const fullText = (
      (titleEl?.textContent || '') + ' ' +
      (authorEl?.textContent || '') + ' ' + tip
    ).toLowerCase();

    const match = words.every(w => fullText.includes(w));

    if (match) {
      card.classList.add('search-match');
      visible++;
      if (!firstMatch) firstMatch = card;
      if (titleEl)  titleEl.innerHTML  = _highlight(titleEl.textContent, words);
      if (authorEl) authorEl.innerHTML = _highlight(authorEl.textContent, words);
      // Show tip in list mode
      if (tip) {
        const tipEl = document.createElement('span');
        tipEl.className = 'cat-search-tip';
        tipEl.textContent = tip;
        card.querySelector('.cat-card-body')?.appendChild(tipEl);
      }
    }
  });

  // Counter
  if (count) {
    if (searching) {
      if (visible === 0) {
        count.textContent = 'Sin resultados — prueba con otra palabra';
        count.className = 'no-results';
      } else {
        count.textContent = `${visible} título${visible !== 1 ? 's' : ''} encontrado${visible !== 1 ? 's' : ''}`;
        count.className = '';
      }
    } else {
      count.textContent = aulaOn ? 'Modo aula activo' : '';
      count.className = '';
    }
  }

  // Scroll to first result
  if (firstMatch && searching) {
    setTimeout(() => firstMatch.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 80);
  }
}

function _highlight(text, words) {
  let result = text.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  words.forEach(w => {
    const rx = new RegExp('(' + w.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + ')', 'gi');
    result = result.replace(rx, '<mark class="search-hl">$1</mark>');
  });
  return result;
}

function _restoreText(card) {
  const titleEl  = card.querySelector('.cat-title');
  const authorEl = card.querySelector('.cat-author');
  if (titleEl?.querySelector('.search-hl'))
    titleEl.textContent = titleEl.textContent;
  if (authorEl?.querySelector('.search-hl'))
    authorEl.textContent = authorEl.textContent;
}

function clearSearch() {
  const input = document.getElementById('catalogSearch');
  if (input) { input.value = ''; input.focus(); }
  searchCatalog('');
}

// Escape key clears search
document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') {
    const input = document.getElementById('catalogSearch');
    if (input && document.activeElement === input) clearSearch();
  }
});

// ── Impresión de modales ─────────────────────────────────────────
// Extrae el contenido del modal al body, imprime, y lo restaura.
// Evita completamente los problemas de display:none en @media print.
function printModal(cls) {
  // Mapear clase → ID del modal con el contenido real
  const MODAL_MAP = {
    'printing-ficha':    'fichaModal',
    'printing-rubrica':  'rubricaModal',
    'printing-expres':   'expresModal',
    'printing-sec':      'secModal',
    'printing-lectura':  'lecturaModal',
  };

  const modalId = MODAL_MAP[cls];
  if (!modalId) { window.print(); return; }

  const modal = document.getElementById(modalId);
  if (!modal) { window.print(); return; }

  // Elementos a ocultar al imprimir (no el modal)
  const HIDE_SELECTORS = '.ficha-actions, .rubrica-actions, .rubrica-controls, ' +
    '.sec-actions, .expres-actions, .lectura-actions, .lectura-nivel-tabs, ' +
    'button.ficha-print-btn, button.rubrica-print-btn, button.sec-print-btn, ' +
    'button.expres-print-btn, button.lectura-print-btn, ' +
    '.ficha-header button, .rubrica-header button, .sec-header button, .lectura-header button';

  // Clonar contenido del modal
  const clone = modal.cloneNode(true);

  // Ocultar botones de acción en el clon
  clone.querySelectorAll(HIDE_SELECTORS).forEach(el => el.style.display = 'none');

  // Crear contenedor de impresión
  const printWrap = document.createElement('div');
  printWrap.id = '__print_wrap__';
  printWrap.style.cssText = 'position:fixed;inset:0;background:#fff;z-index:99999;overflow:auto;padding:1.5rem 2rem;box-sizing:border-box;';
  printWrap.appendChild(clone);
  document.body.appendChild(printWrap);

  // Ocultar todo lo demás
  const origBodyOverflow = document.body.style.overflow;
  document.body.style.overflow = 'hidden';

  // CSS de impresión específico
  const style = document.createElement('style');
  style.id = '__print_style__';
  style.textContent = `
    @media print {
      body > *:not(#__print_wrap__) { display: none !important; }
      #__print_wrap__ {
        position: static !important; overflow: visible !important;
        padding: 0 !important; z-index: auto !important;
      }
      #__print_wrap__ * { box-shadow: none !important; max-height: none !important; overflow: visible !important; }
    }
  `;
  document.head.appendChild(style);

  function cleanup() {
    document.body.removeChild(printWrap);
    document.head.removeChild(style);
    document.body.style.overflow = origBodyOverflow;
    window.removeEventListener('afterprint', cleanup);
  }
  window.addEventListener('afterprint', cleanup);

  // Pequeño delay para que el DOM se actualice antes de imprimir
  requestAnimationFrame(() => requestAnimationFrame(() => window.print()));
}
function _activateTab(panelPrefix, tabClass, id, btn) {
  // Deactivate all panels in this group
  document.querySelectorAll('.' + panelPrefix + '-panel').forEach(p => {
    p.classList.remove('active');
    p.setAttribute('aria-hidden', 'true');
  });
  // Deselect all tabs in this group
  document.querySelectorAll('.' + tabClass).forEach(t => {
    t.classList.remove('active');
    t.setAttribute('aria-selected', 'false');
    t.setAttribute('tabindex', '-1');
  });
  // Activate target panel
  const panel = document.getElementById(panelPrefix + '-' + id);
  if (panel) {
    panel.classList.add('active');
    panel.setAttribute('aria-hidden', 'false');
  }
  // Activate clicked button and keep focus on it
  if (btn) {
    btn.classList.add('active');
    btn.setAttribute('aria-selected', 'true');
    btn.setAttribute('tabindex', '0');
    btn.focus();
  }
}

// ── Tabla currículo tabs ─────────────────────────────────────────
function showCur(id, ev) {
  const btn = ev && ev.target ? ev.target : document.querySelector(`[aria-controls="cur-${id}"]`);
  _activateTab('cur', 'cur-tab', id, btn);
}


