// MICROFICHA «LLÉVALO AL AULA»
// Selecciona plantilla por prioridad de uso pedagógico
// ══════════════════════════════════════════════════════════════════
const vitrineActivityTemplates = {
  inclusion: {
    intro: "Una propuesta para trabajar diversidad, barreras y convivencia desde la empatía.",
    questions: [
      "¿Quién tiene voz en esta historia? ¿Quién no la tiene?",
      "¿Qué barreras —físicas, sociales o emocionales— enfrenta el personaje principal?",
      "¿Qué situación del aula o del entorno te recuerda a lo que vive este personaje?"
    ],
    microtask: "Escribe una norma de convivencia que este personaje necesitaría tener garantizada en su entorno.",
    ideal: "Inclusión · diversidad funcional · convivencia"
  },
  genero: {
    intro: "Una propuesta para analizar representación, roles y estereotipos de género.",
    questions: [
      "¿Cómo se representan los personajes en función de su género en esta obra?",
      "¿Qué expectativas sociales pesan sobre cada personaje?",
      "¿Cambiaría la historia si los roles de género se intercambiasen?"
    ],
    microtask: "Reescribe en una frase el argumento cambiando el género del protagonista. ¿Cambia el sentido?",
    ideal: "Género e identidad · representación · estereotipos"
  },
  filosofia: {
    intro: "Una propuesta para trabajar dilemas éticos, toma de posición y pensamiento crítico.",
    questions: [
      "¿Qué dilema moral o decisión difícil enfrenta el personaje?",
      "¿Existe una respuesta correcta? ¿Por qué sí o por qué no?",
      "¿Con qué valor, principio ético o debate actual lo conectarías?"
    ],
    microtask: "Escribe en una frase qué harías tú en esa situación y por qué. Comenta con un compañero.",
    ideal: "Filosofía y ética · dilema moral · pensamiento crítico"
  },
  ciencia: {
    intro: "Una propuesta breve para diferenciar entre dato, hipótesis y ficción.",
    questions: [
      "¿Qué información de esta obra parece verificable?",
      "¿Qué parte parece más narrativa, simbólica o fantástica?",
      "¿Qué dato buscarías en otra fuente para confirmarlo?"
    ],
    microtask: "Anota un dato que comprobarías y explica por qué lo contrastarías.",
    ideal: "Ciencias · alfabetización informacional · pensamiento crítico"
  },
  emocional: {
    intro: "Una propuesta breve para trabajar emociones, relaciones y empatía.",
    questions: [
      "¿Cómo crees que se siente el personaje principal en este momento?",
      "¿Qué gesto, palabra o silencio te hace pensar eso?",
      "¿Qué harías tú si estuvieras en su lugar?"
    ],
    microtask: "Escribe una respuesta empática o un consejo breve para el personaje.",
    ideal: "Educación emocional · tutoría · convivencia"
  },
  visual: {
    intro: "Una propuesta breve para observar cómo la imagen construye significado.",
    questions: [
      "¿Qué ves primero y por qué crees que llama la atención?",
      "¿Qué emoción o idea transmite la composición de la obra?",
      "¿Cómo cambiaría el sentido si se alterara el gesto, el encuadre o el fondo?"
    ],
    microtask: "Pon título a la escena o describe en dos líneas qué cuenta la imagen sin resumir toda la historia.",
    ideal: "Lengua · alfabetización visual · expresión oral"
  },
  lenguas: {
    intro: "Una propuesta para comparar lenguajes narrativos y trabajar la intertextualidad.",
    questions: [
      "¿Qué diferencias encuentras entre lo que dice el texto y lo que muestra la imagen?",
      "¿Qué se perdería si esta obra fuera solo texto, sin dibujos?",
      "¿Con qué obra literaria en otro formato la compararías?"
    ],
    microtask: "Reescribe una escena en forma de diálogo teatral o en narración en primera persona.",
    ideal: "Lengua extranjera · intertextualidad · comparación de formatos"
  },
  historia: {
    intro: "Una propuesta breve para trabajar contexto histórico, memoria y lectura crítica.",
    questions: [
      "¿Qué época, conflicto o cambio social podría estar reflejando esta obra?",
      "¿Qué detalle visual o narrativo te da pistas sobre ese contexto?",
      "¿Qué parte crees que puede ser histórica y cuál interpretativa?"
    ],
    microtask: "Escribe una frase que explique qué podría aprender una clase de Historia a partir de este título.",
    ideal: "Historia · memoria histórica · pensamiento crítico"
  }
};

const FICHA_PRIORITY_V = ['inclusion','genero','filosofia','ciencia','emocional','lenguas','historia','visual'];

const stageHint = {
  infantil:    "Pregunta oral guiada.",
  primaria:    "Respuesta breve + dibujo o viñeta.",
  secundaria:  "Debate + contraste con otra fuente.",
  bachillerato: "Análisis crítico y justificación.",
  universidad: "Análisis crítico y justificación."
};

function buildFicha(uso, nivel) {
  const usoList = (uso || '').split(' ');
  let tpl = null;
  for (const key of FICHA_PRIORITY_V) {
    if (usoList.includes(key)) { tpl = vitrineActivityTemplates[key]; break; }
  }
  if (!tpl) tpl = vitrineActivityTemplates.historia;

  const steps = document.getElementById('vitrineSteps');
  const tarea = document.getElementById('vitrineTarea');
  if (!steps || !tarea) return;

  // Intro line
  const introHtml = tpl.intro
    ? `<p class="vitrina-ficha-intro">${tpl.intro}</p>` : '';

  // Three questions with Mira/Piensa/Relaciona labels
  const labels = [
    { tag: 'Mira',      cls: 'tag-mira' },
    { tag: 'Piensa',    cls: 'tag-piensa' },
    { tag: 'Relaciona', cls: 'tag-relaciona' }
  ];
  steps.innerHTML = introHtml + tpl.questions.map((q, i) => `
    <div class="vitrina-ficha-step">
      <span class="vitrina-ficha-step-tag ${labels[i].cls}">${labels[i].tag}</span>
      <span class="vitrina-ficha-step-text">${q}</span>
    </div>`).join('');

  // Microtask + ideal line
  // Stage hint — show hint(s) for this card's nivel
  const nivelList = (nivel || '').split(' ').filter(Boolean);
  const hints = nivelList
    .map(n => stageHint[n])
    .filter((h, i, a) => h && a.indexOf(h) === i) // deduplicate
    .slice(0, 2); // max 2 stage hints to avoid verbosity
  const hintHtml = hints.length
    ? `<span class="vitrina-ficha-stage">${hints.join(' / ')}</span>` : '';

  tarea.innerHTML = `<strong>Microtarea</strong>${tpl.microtask}`
    + hintHtml
    + (tpl.ideal ? `<span class="vitrina-ficha-ideal">${tpl.ideal}</span>` : '');
}

function vitrineSearchCatalog() {
  const title = document.getElementById('vitrineTitle').textContent
    .replace(/^★\s*/, '').replace(/[:·].*/,'').trim();
  if (!title) return;
  // Populate catalog search input
  const input = document.getElementById('catalogSearch');
  if (input) {
    input.value = title;
    searchCatalog(title);
  }
  // Close the drawer
  closeVitrina();
  // Scroll to catalog section
  const cat = document.getElementById('catalogo');
  if (cat) setTimeout(() => cat.scrollIntoView({ behavior: 'smooth', block: 'start' }), 120);
}

// Event delegation: handles vitrina clicks robustly regardless of DOM timing
// Also apply role/tabindex to all vitrina cards
document.addEventListener('DOMContentLoaded', () => {
  ensureVitrinaUI();
  document.querySelectorAll('.card[data-vitrina]').forEach(card => {
    card.setAttribute('role', 'button');
    card.setAttribute('tabindex', '0');
  });
});

// Delegation on document — catches clicks on any .card with data-vitrina
document.addEventListener('click', e => {
  // Don't trigger if click originates inside the vitrina drawer
  if (e.target.closest('#vitrineDrawer') || e.target.closest('#vitrineOverlay')) return;
  const card = e.target.closest('.card[data-vitrina]');
  if (card) openVitrina(card);
});
document.addEventListener('keydown', e => {
  if (e.key !== 'Enter' && e.key !== ' ') return;
  // Only activate if focus is on a vitrina card (not in a text input or button)
  const tag = e.target.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'BUTTON' || tag === 'SELECT') return;
  const card = e.target.closest('.card[data-vitrina]');
  if (card) { e.preventDefault(); openVitrina(card); }
});






// ══════════════════════════════════════════════════════════════════
const USO_LABELS_F = {
  historia:'Historia', filosofia:'Filosofía y ética', emocional:'Educación emocional',
  lenguas:'Lengua extranjera', inclusion:'Inclusión', visual:'Alfabetización visual',
  ciencia:'Ciencia y tecnología', genero:'Género e identidad'
};
