// ══════════════════════════════════════════════════════════════════
// CONEXIÓN API GEMINI
// ══════════════════════════════════════════════════════════════════
async function geminiRequest(api_key, promptText) {
  // La URL definitiva que usa Google en producción para Gemini 1.5 Flash
  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${api_key}`;

  try {
    const resp = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [{ text: promptText }] }]
      })
    });
    const data = await resp.json();
    if (resp.ok && data.candidates) {
      return data.candidates[0].content.parts[0].text;
    }
    // Si falla, lanzamos el error que nos diga Google
    throw new Error(data.error?.message || `Error ${resp.status}`);
  } catch (e) {
    Logger.error('Gemini', 'Fallo de API:', e);
    throw new Error(`Google no responde: ${e.message}`);
  }
}


