// GENERADORES IA (Rúbricas y Secuencias)
// ══════════════════════════════════════════════════════════════════
async function generarRubrica() {
  const apiKey  = sessionStorage.getItem(MANGA_ASIST_KEY) || '';
  const titulo  = document.getElementById('rubricaTitulo').value.trim();
  const nivel   = document.getElementById('rubricaNivel').value;
  const comps   = Array.from(document.querySelectorAll('#rubricaCompChecks input:checked')).map(cb => cb.value);
  const comp    = comps.length ? comps.join(' · ') : 'CCL';
  const bodyEl  = document.getElementById('rubricaBody');
  const btn     = document.getElementById('rubricaGenBtn');

  if (!titulo) {
    bodyEl.innerHTML = '<p class="rubrica-placeholder">Introduce el título de un manga.</p>';
    return;
  }

  btn.disabled = true;
  btn.textContent = 'Generando…';
  bodyEl.innerHTML = `<p class="rubrica-placeholder">Generando rúbrica${apiKey ? ' con Gemini' : ' con Claude'}…</p>`;

  const _catR = (typeof CATALOGO !== 'undefined')
    ? CATALOGO.find(t => t.titulo === titulo || titulo.toLowerCase().includes(t.titulo.toLowerCase().substring(0,12)))
    : null;
  const _tipR  = _catR?.tip    ? ` Descripción pedagógica del título: "${_catR.tip}".` : '';
  const _odsR  = _catR?.ods?.length ? ` ODS vinculados: ${_catR.ods.map(n=>'ODS '+n).join(', ')}.` : '';
  const _sensR = _catR?.sensitive   ? ` Nota: obra con contenido sensible (${_catR.sens_label||'16+'}), adapta los criterios.` : '';

  const prompt = `Actúa como experto en pedagogía LOMLOE. Genera una rúbrica de evaluación detallada para trabajar el manga "${titulo}" en ${nivel}.${_tipR}${_odsR}${_sensR} Competencias clave: ${comp}. Devuelve SOLO código HTML limpio (sin bloques de código markdown). Incluye un párrafo de contexto y una tabla 4x4 con niveles: Inicial, En desarrollo, Conseguido y Excelente. Para cada criterio indica a qué competencia corresponde.`;

  try {
    let html = await _withRetry(
      () => aiRequest(prompt, apiKey),
      { statusEl: bodyEl, maxRetries: 3, baseDelay: 1000, onRetry: generarRubrica }
    );
    html = String(html).replace(/```html?[\r\n]?/g, '').replace(/```[\r\n]?/g, '').trim();
    if (!html) throw new Error('La IA devolvió una respuesta vacía.');
    bodyEl.innerHTML =
      `<div class="rubrica-content">${html}` +
      `<p class="ia-transparency-note" role="note">` +
      `✦ Generado con <strong>${_lastAiProvider} IA</strong> · ` +
      `Revisa y adapta antes de usar en el aula · EU AI Act Art. 50</p></div>`;
  } catch (e) {
    bodyEl.innerHTML = _errorHtml(e, generarRubrica);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Generar rúbrica ✦';
  }
}

async function generarSecuencia() {
  const apiKey   = sessionStorage.getItem(MANGA_ASIST_KEY) || '';
  const titulo   = document.getElementById('secTitulo').value.trim();
  const etapa    = document.getElementById('secEtapa').value;
  const sesiones = document.getElementById('secSesiones').value;
  const comps    = Array.from(document.querySelectorAll('#secCompChecks input:checked')).map(cb => cb.value);
  const comp     = comps.length ? comps.join(' · ') : 'CCL';
  const compPrincipal = comps.length ? comps[0] : 'CCL';
  const bodyEl   = document.getElementById('secBody');
  const btn      = document.getElementById('secGenBtn');

  if (!titulo) {
    bodyEl.innerHTML = '<p class="sec-placeholder">Introduce el título de un manga.</p>';
    return;
  }

  btn.disabled = true;
  btn.textContent = 'Generando…';
  bodyEl.innerHTML = `<p class="sec-placeholder">Diseñando secuencia didáctica${apiKey ? ' con Gemini' : ' con Claude'}…</p>`;

  // M19: Enriquecer el prompt con los datos del catálogo si el título existe
  const _catEntry = (typeof CATALOGO !== 'undefined')
    ? CATALOGO.find(t => t.titulo === titulo || titulo.toLowerCase().includes(t.titulo.toLowerCase().substring(0,12)))
    : null;
  const _catTip    = _catEntry?.tip    ? `\nDESCRIPCIÓN PEDAGÓGICA: ${_catEntry.tip}` : '';
  const _catOds    = _catEntry?.ods?.length ? `\nODS VINCULADOS: ${_catEntry.ods.map(n=>'ODS '+n).join(', ')}` : '';
  const _catBadges = _catEntry?.badges?.length ? `\nUSO PEDAGÓGICO: ${_catEntry.badges.join(', ')}` : '';
  const _catNivel  = _catEntry?.nivel  ? `\nNIVEL EN CATÁLOGO: ${_catEntry.nivel}` : '';
  const _catSens   = _catEntry?.sensitive ? `\nNOTA: Esta obra tiene contenido sensible (${_catEntry.sens_label || '16+'}). Adapta las actividades en consecuencia.` : '';

  const prompt = `Eres un experto en didáctica y currículo escolar de Canarias (España).
Genera una secuencia didáctica completa y aplicable en un aula canaria usando el manga "${titulo}" como recurso principal.

DATOS DEL FONDO ULPGC:${_catTip}${_catBadges}${_catOds}${_catNivel}${_catSens}

CONTEXTO CURRICULAR (${etapa}):
${etapa.includes('Infantil') ? 'Decreto 196/2022 Canarias. Áreas: Crecimiento en Armonía · Descubrimiento del Entorno · Comunicación y Representación. Metodología: aprendizaje globalizado, rincones, juego simbólico.' : ''}${etapa.includes('Primaria') ? 'Decreto 83/2022 Canarias + RD 157/2022. Énfasis en entorno insular, situaciones de aprendizaje contextualizadas, interdisciplinariedad.' : ''}${(etapa.includes('ESO') || etapa.includes('Secundaria')) ? 'RD 217/2022 + normativa canaria. Situaciones de aprendizaje, ODS, ciudadanía global.' : ''}${etapa.includes('Bachillerato') ? 'RD 217/2022 bachillerato. Pensamiento crítico, investigación, preparación universitaria.' : ''}
Competencias clave trabajadas: ${comp}. Competencia principal: ${compPrincipal}. Sesiones: ${sesiones} × 50 min.

ESTRUCTURA HTML (sin markdown):
1. <h3>Título y justificación</h3> — Cita la normativa canaria aplicable.
2. <h4>Objetivos didácticos</h4> — 4-5 objetivos.
3. <h4>Competencias clave</h4> — ${comp}. Describe la contribución de cada una.
4. <h4>Tabla de sesiones</h4> — Sesión|Título|Actividad|Recursos|Indicador evaluación.
5. <h4>Metodología</h4> — Metodologías activas canarias.
6. <h4>Evaluación</h4> — Criterios LOMLOE + instrumentos vinculados a ${comp}.
${etapa.includes('Infantil') ? '7. <h4>Conexión áreas Infantil</h4>' : ''}${etapa.includes('Primaria') ? '7. <h4>Interdisciplinariedad</h4>' : ''}
Solo HTML: <h3><h4><p><ul><li><table><thead><tbody><tr><th><td>`;

  try {
    let html = await _withRetry(
      () => aiRequest(prompt, apiKey),
      { statusEl: bodyEl, maxRetries: 3, baseDelay: 1000, onRetry: generarSecuencia }
    );
    html = String(html).replace(/```html?[\r\n]?/g, '').replace(/```[\r\n]?/g, '').trim();
    if (!html) throw new Error('La IA devolvió una respuesta vacía.');
    bodyEl.innerHTML =
      `<div class="sec-content">${html}` +
      `<p class="ia-transparency-note" role="note">` +
      `✦ Generado con <strong>${_lastAiProvider} IA</strong> · ` +
      `Revisa y adapta antes de usar en el aula · EU AI Act Art. 50</p></div>`;
  } catch (e) {
    bodyEl.innerHTML = _errorHtml(e, generarSecuencia);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Generar secuencia ✦';
  }
}

// ══════════════════════════════════════════════════════════════════
// ASISTENTE PEDAGÓGICO IA (Chat)
// ══════════════════════════════════════════════════════════════════
(function() {
  const SESS_KEY = MANGA_ASIST_KEY;

  let panel, overlay, messages, input, sendBtn, keyInput, keyStatus, keyArea;
  let conversationHistory = [];
  let apiKey = sessionStorage.getItem(SESS_KEY) || '';
  let hasWelcomed = false;

  function extractCatalogContext(limit = 120) {
    const cards = Array.from(document.querySelectorAll('.cat-card')).slice(0, limit);
    if (!cards.length) return '';

    return cards.map(card => {
      const title = card.querySelector('.cat-title')?.textContent?.trim() || '';
      const author = card.querySelector('.cat-author')?.textContent?.trim() || '';
      const usos = Array.from(card.querySelectorAll('.cat-badge')).map(el => el.textContent.trim()).join(', ');
      const niveles = Array.from(card.querySelectorAll('.niv-badge')).map(el => el.textContent.trim()).join(', ');
      return `• ${title} — ${author}${usos ? ' — uso: ' + usos : ''}${niveles ? ' — nivel: ' + niveles : ''}`;
    }).join('\n');
  }

  function buildSystemPrompt() {
    const catalogContext = extractCatalogContext();
    return `Eres el Asistente Pedagógico de la Biblioteca del Campus del Obelisco (ULPGC), especializado en el uso didáctico del manga.
Tu función es ayudar a docentes y visitantes a:
- encontrar títulos adecuados para sus necesidades educativas,
- diseñar actividades, secuencias y situaciones de aprendizaje con manga,
- conectar títulos con el currículo LOMLOE y las competencias clave,
- justificar pedagógicamente el uso del manga en el aula.

Responde siempre en español. Sé útil, concreto y profesional. Prioriza títulos reales del fondo mostrado en esta página.

FONDO DISPONIBLE EN ESTA PÁGINA:
${catalogContext || 'Consulta el catálogo visible de la página para seleccionar títulos reales.'}`;
  }

  function renderMd(text) {
    // Nota: el texto viene de la API de IA (fuente externa).
    // Se sanitiza DESPUÉS del renderizado de Markdown para conservar
    // el HTML legítimo (<strong>, <em>, <br>) y eliminar etiquetas peligrosas.
    const rendered = text
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.+?)\*/g, '<em>$1</em>')
      .replace(/\n/g, '<br>');
    return sanitizeHtml(rendered);
  }

  function addMsg(role, text, typing) {
    const div = document.createElement('div');
    div.className = 'asist-msg ' + (typing ? 'typing' : role);
    div.innerHTML = typing ? text : renderMd(text);
    if (typing) div.id = 'asist-typing';
    messages.appendChild(div);
    messages.scrollTop = messages.scrollHeight;
    return div;
  }

  function removeTyping() {
    const t = document.getElementById('asist-typing');
    if (t) t.remove();
  }

  function addSuggestions(items) {
    const wrap = document.createElement('div');
    wrap.style.cssText = 'align-self:flex-start;max-width:92%;margin-top:-.3rem';
    items.forEach(s => {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'asist-suggestion';
      btn.textContent = s;
      btn.onclick = () => { wrap.remove(); sendMessage(s); };
      wrap.appendChild(btn);
    });
    messages.appendChild(wrap);
    messages.scrollTop = messages.scrollHeight;
  }

  function showWelcome() {
    if (hasWelcomed) return;
    hasWelcomed = true;
    addMsg('assistant', '¡Hola! Soy el asistente pedagógico de la **Biblioteca del Campus del Obelisco**. Puedo ayudarte a localizar títulos del fondo, proponer recorridos y diseñar actividades o secuencias alineadas con LOMLOE.');
    addSuggestions([
      'Busco manga para Infantil',
      'Quiero trabajar memoria histórica en ESO',
      'Recomiéndame algo para Filosofía'
    ]);
  }

  async function sendMessage(text) {
    if (!text.trim()) return;

    input.value = '';
    input.style.height = 'auto';
    sendBtn.disabled = true;
    addMsg('user', text);
    conversationHistory.push({ role: 'user', content: text });
    addMsg('assistant', 'Consultando el fondo…', true);

    try {
      let fullPrompt = buildSystemPrompt() + "\n\nHISTORIAL DE LA CONVERSACIÓN:\n";
      conversationHistory.forEach(m => {
        fullPrompt += `${m.role.toUpperCase()}: ${m.content}\n`;
      });
      fullPrompt += "\nResponde al último mensaje del usuario de forma útil, precisa y en español.";

      const reply = await aiRequest(fullPrompt, apiKey);
      removeTyping();

      const finalReply = String(reply || '').trim() || 'No he recibido texto de respuesta de la IA.';
      conversationHistory.push({ role: 'assistant', content: finalReply });
      addMsg('assistant', finalReply);

      if (conversationHistory.length === 2) {
        addSuggestions([
          'Dame un itinerario para Primaria',
          'Recomiéndame manga para empatía',
          '¿Qué puedo usar en la ULPGC?',
          'Diseña una actividad para ESO'
        ]);
      }
    } catch (e) {
      removeTyping();
      const errString = e.message || 'Error desconocido.';
      addMsg('assistant', `<span style="color:#e06060">Respuesta de Google: ${errString}</span>`);
    } finally {
      sendBtn.disabled = false;
      input.focus();
    }
  }

  function saveKey() {
    const k = keyInput.value.trim();
    if (!k.startsWith('AIza')) {
      keyStatus.textContent = 'La clave debe empezar por AIza…';
      keyStatus.className = 'asist-key-status err';
      return;
    }

    apiKey = k;
    sessionStorage.setItem(SESS_KEY, k);
    // La clave vive en sessionStorage: persiste mientras la pestaña esté abierta,
    // pero se elimina al cerrarla. Esto es intencional: protege la clave de otros
    // usuarios que accedan al mismo equipo en una sesión posterior.
    keyStatus.textContent = '✓ Gemini activado — la clave se borrará al cerrar la pestaña';
    keyStatus.className = 'asist-key-status ok';
    keyInput.value = '';

    setTimeout(() => {
      keyArea.style.display = 'none';
      showWelcome();
    }, 600);
  }

  function openPanel() {
    overlay.classList.add('open');
    panel.classList.add('open');
    document.body.style.overflow = 'hidden';
    // Claude funciona sin clave — mostrar chat siempre
    keyArea.style.display = 'none';
    sendBtn.disabled = false;
    if (conversationHistory.length === 0) showWelcome();
    setTimeout(() => input.focus(), 300);
  }

  function closePanel() {
    overlay.classList.remove('open');
    panel.classList.remove('open');
    document.body.style.overflow = '';
  }

  function buildUI() {
    overlay = document.createElement('div');
    overlay.id = 'asist-overlay';
    overlay.onclick = closePanel;
    document.body.appendChild(overlay);

    panel = document.createElement('div');
    panel.id = 'asist-panel';
    panel.setAttribute('role', 'dialog');
    panel.setAttribute('aria-modal', 'true');
    panel.setAttribute('aria-labelledby', 'asist-dialog-title');
    panel.innerHTML = `
      <div id="asist-head"><h2 id="asist-dialog-title">✦ Asistente Pedagógico</h2><button type="button" id="asist-close">Cerrar ✕</button></div>
      <div id="asist-key-area"><p>Clave de <strong>Google AI Studio / Gemini</strong>. <a href="https://aistudio.google.com/apikey" target="_blank" style="color:#7AB4FF">Obtén tu clave →</a></p>
        <div id="asist-key-row"><input type="password" id="asist-key-input" placeholder="AIzaSy…"><button type="button" id="asist-key-save">Activar</button></div>
        <p id="asist-key-status" class="asist-key-status"></p></div>
      <div id="asist-messages"></div>
      <div id="asist-input-area"><textarea id="asist-input" placeholder="Escribe tu consulta…"></textarea><button type="button" id="asist-send">Enviar</button></div>`;
    document.body.appendChild(panel);

    messages = document.getElementById('asist-messages');
    input = document.getElementById('asist-input');
    sendBtn = document.getElementById('asist-send');
    keyInput = document.getElementById('asist-key-input');
    keyStatus = document.getElementById('asist-key-status');
    keyArea = document.getElementById('asist-key-area');

    document.getElementById('asist-close').onclick = closePanel;
    document.getElementById('asist-key-save').onclick = saveKey;
    keyInput.addEventListener('keydown', e => { if (e.key === 'Enter') saveKey(); });
    input.addEventListener('input', function() {
      this.style.height = 'auto';
      this.style.height = Math.min(this.scrollHeight, 120) + 'px';
    });
    input.addEventListener('keydown', e => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendMessage(input.value);
      }
    });
    sendBtn.onclick = () => sendMessage(input.value);
    document.addEventListener('keydown', e => {
      if (e.key === 'Escape' && panel.classList.contains('open')) closePanel();
    });

    if (apiKey) keyArea.style.display = 'none';

    const fabBtn = document.getElementById('asist-fab');
    if (fabBtn) fabBtn.onclick = openPanel;
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', buildUI);
  } else {
    buildUI();
  }
})();

