function buildMapaGrid(force = false) {
  const container = document.getElementById('mapaContainer');
  if (!container || (!force && container.dataset.built)) return;
  const USO_COLORS = {historia:'#5A3A1A',filosofia:'#4A2A6A',emocional:'#7A5A0A',
    lenguas:'#2E6E3A',inclusion:'#3A4A8A',visual:'#5E3A8A',ciencia:'#1A5A8B',genero:'#8B1A4A'};
  const USO_LABELS = {historia:'Historia',filosofia:'Filosofía',emocional:'Ed. emocional',
    lenguas:'Lengua extranjera',inclusion:'Inclusión',visual:'Alfab. visual',
    ciencia:'Ciencia y tecnología',genero:'Género e identidad'};
  const groups = {};
  document.querySelectorAll('.cat-card').forEach(card => {
    const uso   = (card.getAttribute('data-uso')||'').split(' ')[0];
    const title = card.querySelector('.cat-title')?.textContent||'';
    if (!uso||!title) return;
    if (!groups[uso]) groups[uso]=[];
    groups[uso].push(title);
  });
  let html = '';
  for (const [uso, titles] of Object.entries(groups)) {
    const color = USO_COLORS[uso]||'#5a5a5a';
    const label = USO_LABELS[uso]||uso;
    html += `<div class="mapa-group"><div class="mapa-group-header" style="background:${color}">
      <span class="mapa-group-label">${label}</span><span class="mapa-group-count">${titles.length}</span></div>
      <div class="mapa-chips">${titles.map(t=>`<button type="button" class="mapa-chip"
        style="border-color:${color}30" onclick="filterByTitle('${t.replace(/'/g,"\\'")}');closeMapa()"
        title="${t}">${t}</button>`).join('')}</div></div>`;
    /* Nota: filterByTitle() ya cierra mapaOverlay; closeMapa() es redundante pero inocuo */
  }
  container.innerHTML = html;
  container.dataset.built = '1';
}

// ── Vista ODS del mapa ──────────────────────────────────────────
function buildMapaGridOds(force = false) {
  const container = document.getElementById('mapaContainer');
  if (!container || (!force && container.dataset.builtOds)) return;
  const ODS_COLORS = {3:'#4C9F38',4:'#C5192D',5:'#FF3A21',8:'#A21942',
    9:'#FD6925',10:'#DD1367',11:'#FD9D24',13:'#3F7E44',15:'#56C02B',16:'#00689D'};
  const ODS_LABELS = {3:'ODS 3 · Salud y bienestar',4:'ODS 4 · Educación de calidad',
    5:'ODS 5 · Igualdad de género',8:'ODS 8 · Economía y crecimiento sostenible',
    9:'ODS 9 · Industria e innovación',10:'ODS 10 · Reducción de desigualdades',
    11:'ODS 11 · Ciudades sostenibles',13:'ODS 13 · Acción por el clima',
    15:'ODS 15 · Ecosistemas terrestres',16:'ODS 16 · Paz y justicia'};
  const groups = {};
  document.querySelectorAll('.cat-card').forEach(card => {
    const odsAttr = card.getAttribute('data-ods') || '';
    const title   = card.querySelector('.cat-title')?.textContent || '';
    if (!title) return;
    odsAttr.split(' ').filter(Boolean).forEach(n => {
      if (!groups[n]) groups[n] = [];
      groups[n].push(title);
    });
  });
  // Sort by ODS number
  let html = '';
  Object.keys(groups).map(Number).sort((a,b)=>a-b).forEach(n => {
    const titles = groups[n];
    const color  = ODS_COLORS[n] || '#666';
    const label  = ODS_LABELS[n] || ('ODS ' + n);
    html += `<div class="mapa-group"><div class="mapa-group-header" style="background:${color}">
      <span class="mapa-group-label">${label}</span><span class="mapa-group-count">${titles.length}</span></div>
      <div class="mapa-chips">${titles.map(t=>`<button type="button" class="mapa-chip"
        style="border-color:${color}30" onclick="filterOds('${n}');closeMapa()"
        title="Filtrar por ODS ${n}: ${t}">${t}</button>`).join('')}</div></div>`;
  });
  container.innerHTML = html;
  container.dataset.builtOds = '1';
}

let mapaView = 'uso'; // 'uso' | 'ods'
function setMapaView(view) {
  mapaView = view;
  document.getElementById('mapaViewUso')?.classList.toggle('active', view === 'uso');
  document.getElementById('mapaViewOds')?.classList.toggle('active', view === 'ods');
  const container = document.getElementById('mapaContainer');
  if (container) {
    // Clear built cache for the view we're switching to so it rebuilds fresh
    if (view === 'uso') {
      delete container.dataset.built;
      buildMapaGrid();
    } else {
      delete container.dataset.builtOds;
      buildMapaGridOds();
    }
  }
}

