document.addEventListener('DOMContentLoaded', function() {
  document.querySelectorAll('a.wr[href^="#"]').forEach(function(link) {
    link.addEventListener('click', function(e) {
      const target = document.getElementById(this.getAttribute('href').slice(1));
      if (!target) return;
      e.preventDefault();
      target.scrollIntoView({ behavior:'smooth', block:'start' });
      target.style.transition = 'box-shadow .3s';
      target.style.boxShadow  = '0 0 0 3px rgba(184,134,11,.4)';
      setTimeout(() => { target.style.boxShadow = ''; }, 1800);
    });
  });
});

document.addEventListener('DOMContentLoaded', function() {
  const toggle = document.getElementById('tools-fab-toggle');
  const items  = document.getElementById('fabItems');
  if (!toggle || !items) return;

  toggle.addEventListener('click', function(e) {
    e.stopPropagation();
    const isOpen = items.classList.toggle('open');
    toggle.classList.toggle('open', isOpen);
    toggle.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
    toggle.textContent = isOpen ? '×' : '+';
  });

  document.addEventListener('click', function(e) {
    if (!e.target.closest('#tools-fab')) {
      items.classList.remove('open');
      toggle.classList.remove('open');
      toggle.setAttribute('aria-expanded', 'false');
      toggle.textContent = '+';
    }
  });

  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
      items.classList.remove('open');
      toggle.classList.remove('open');
      toggle.setAttribute('aria-expanded', 'false');
      toggle.textContent = '+';
    }
  });
});

// ══════════════════════════════════════════════════════════════════
// CONTADOR DE TÍTULOS EXPLORADOS POR ÁREA
// ══════════════════════════════════════════════════════════════════
(function() {

  const USO_CONFIG = {
    historia:  { label: 'Historia',        color: '#5A3A1A' },
    filosofia: { label: 'Filosofía',       color: '#4A2A6A' },
    emocional: { label: 'Ed. emocional',   color: '#7A5A0A' },
    lenguas:   { label: 'Lenguas',         color: '#2E6E3A' },
    inclusion: { label: 'Inclusión',       color: '#3A4A8A' },
    visual:    { label: 'Alfab. visual',   color: '#5E3A8A' },
    ciencia:   { label: 'Ciencia',         color: '#1A5A8B' },
    genero:    { label: 'Género',          color: '#8B1A4A' },
  };

  const ODS_COLORS = {
    3:'#4C9F38', 4:'#C5192D', 5:'#FF3A21', 8:'#A21942',
    9:'#FD6925', 10:'#DD1367', 11:'#FD9D24', 13:'#3F7E44',
    15:'#56C02B', 16:'#00689D'
  };

  // ── Título → uso + ods (leído del DOM) ───────────────────────
  function getCardIndex() {
    const idx = {};
    document.querySelectorAll('.cat-card').forEach(card => {
      const title = card.querySelector('.cat-title')?.textContent?.trim();
      if (!title) return;
      const uso = (card.getAttribute('data-uso') || '').split(/\s+/)[0] || 'visual';
      const ods = (card.getAttribute('data-ods') || '').split(/\s+/).filter(Boolean).map(Number);
      idx[title] = { uso, ods };
    });
    return idx;
  }

  // ── Recopilar títulos explorados ─────────────────────────────
  // Fuente 1: sessionLog.viewed (sesión actual)
  // Fuente 2: manga_notas__* en localStorage (sesiones anteriores)
  function getExploredTitles() {
    const titles = new Set();

    // Session titles
    if (typeof sessionLog !== 'undefined') {
      (sessionLog.viewed || []).forEach(e => { if (e.title) titles.add(e.title); });
    }

    // localStorage notes (cross-session)
    SafeStorage.keys()
      .filter(key => key && key.startsWith('manga_notas__'))
      .forEach(key => {
        // Reverse-engineer title from key (best effort)
        const raw = key.replace('manga_notas__', '').replace(/_/g, ' ');
        // Match against known card titles
        titles.add('__ls__' + raw); // mark as localStorage-sourced
      });

    return titles;
  }

  // ── Render ────────────────────────────────────────────────────
  function renderCounter() {
    const widget = document.getElementById('explorerCounter');
    const barsEl = document.getElementById('excBars');
    const odsEl  = document.getElementById('excOdsRow');
    const totalEl= document.getElementById('excTotal');
    if (!widget || !barsEl) return;

    const cardIdx = getCardIndex();

    // Session titles only (precise matching)
    const sessionTitles = new Set();
    if (typeof sessionLog !== 'undefined') {
      (sessionLog.viewed || []).forEach(e => { if (e.title) sessionTitles.add(e.title); });
    }

    // localStorage titles (cross-session) — matched against card index
    const lsTitles = new Set();
    SafeStorage.keys()
      .filter(k => k?.startsWith('manga_notas__'))
      .forEach(k => {
        const raw = k.replace('manga_notas__', '').replace(/_/g, ' ');
        // Find best match in cardIdx
        for (const t of Object.keys(cardIdx)) {
          if (t.slice(0, 80).replace(/\s+/g, ' ') === raw) {
            lsTitles.add(t); break;
          }
        }
      });

    // Union
    const allTitles = new Set([...sessionTitles, ...lsTitles]);
    const total = allTitles.size;

    if (total === 0) {
      widget.classList.remove('has-data');
      return;
    }
    widget.classList.add('has-data');

    // Count per uso
    const usoCounts  = {};
    const odsSeen    = new Set();
    for (const t of allTitles) {
      const info = cardIdx[t];
      if (!info) continue;
      usoCounts[info.uso] = (usoCounts[info.uso] || 0) + 1;
      info.ods.forEach(n => odsSeen.add(n));
    }

    const maxCount = Math.max(...Object.values(usoCounts), 1);
    const sessionOnly = sessionTitles.size;
    const lsOnly = lsTitles.size - [...lsTitles].filter(t => sessionTitles.has(t)).length;

    // Label
    let subtitle = `${total} título${total !== 1 ? 's' : ''}`;
    if (lsOnly > 0) subtitle += ` · ${sessionOnly} esta sesión · ${lsOnly} de sesiones anteriores`;
    totalEl.textContent = subtitle;

    // Bars — sorted by count desc
    const sorted = Object.entries(usoCounts).sort((a, b) => b[1] - a[1]);
    barsEl.innerHTML = sorted.map(([uso, count]) => {
      const cfg = USO_CONFIG[uso] || { label: uso, color: '#666' };
      const pct  = Math.round((count / maxCount) * 100);
      return `<div class="exc-row">
        <span class="exc-uso-name" style="color:${cfg.color}">${cfg.label}</span>
        <div class="exc-bar-track">
          <div class="exc-bar-fill" style="width:${pct}%;background:${cfg.color}"></div>
        </div>
        <span class="exc-count">${count}</span>
      </div>`;
    }).join('');

    // ODS chips
    if (odsSeen.size > 0) {
      const sortedOds = [...odsSeen].sort((a,b) => a-b);
      odsEl.innerHTML =
        `<span class="exc-ods-label">ODS cubiertos</span>` +
        sortedOds.map(n =>
          `<span class="exc-ods-chip" style="background:${ODS_COLORS[n]||'#666'}" title="ODS ${n}">ODS ${n}</span>`
        ).join('');
      odsEl.style.display = 'flex';
    } else {
      odsEl.style.display = 'none';
    }
  }

  // ── Reset (solo sesión, no borra notas) ───────────────────────
  window.resetExplorerCounter = function() {
    if (typeof sessionLog !== 'undefined') {
      sessionLog.viewed = [];
    }
    renderCounter();
  };

  // ── Hook: actualizar cada vez que logActivity registra viewed ─
  const _origLog = window.logActivity;
  document.addEventListener('DOMContentLoaded', function() {
    // Patch logActivity after DOM ready (when it's defined)
    const patchInterval = setInterval(() => {
      if (typeof logActivity === 'function' && !logActivity._patched) {
        const __orig = logActivity;
        window.logActivity = function(type, data) {
          __orig(type, data);
          if (type === 'viewed') setTimeout(renderCounter, 50);
        };
        window.logActivity._patched = true;
        clearInterval(patchInterval);
      }
    }, 100);

    // Also hook openFicha, openLectura, openExpres directly
    ['openFicha', 'openLectura', 'openExpres'].forEach(fn => {
      const orig = window[fn];
      if (typeof orig === 'function') {
        window[fn] = function(...args) {
          orig.apply(this, args);
          setTimeout(renderCounter, 150);
        };
      }
    });

    // Initial render (picks up localStorage notes)
    renderCounter();
  });

})();

// ══════════════════════════════════════════════════════════════════
// ACTIVIDAD EXPRÉS (5 min)
// ══════════════════════════════════════════════════════════════════
(function() {

  // ── Tipos de actividad ────────────────────────────────────────
  const TIPOS = {
    opinion:   { label: 'Opinión',        color: '#5A3A8A' },
    visual:    { label: 'Análisis visual', color: '#1A5A8B' },
    escritura: { label: 'Escritura',       color: '#5A3A1A' },
  };

  // ── Plantillas por uso pedagógico ─────────────────────────────
  // Cada entrada: [tipo, instrucciones HTML, competencia]
  const PLANTILLAS = {
    historia: [
      ['opinion',
       '<strong>Pregunta de opinión (1+4 min)</strong><br>Lee la descripción de <em>{titulo}</em>. ¿Crees que el manga es una fuente histórica fiable? Escribe tu postura en 2 frases. Después: 4 personas comparten su respuesta en voz alta. El grupo busca puntos en común.',
       'CSC · Pensamiento histórico y crítico'],
      ['visual',
       '<strong>Fuente o ficción (5 min)</strong><br>El argumento de <em>{titulo}</em> mezcla hechos reales y ficción. En parejas: identificad qué elementos de la descripción parecen históricamente documentados y cuáles probablemente son inventados. Poned en común en 2 minutos.',
       'CSC · Análisis de fuentes históricas'],
      ['escritura',
       '<strong>Entrada de diario (5 min)</strong><br>Escribe una entrada de diario como si fueras un personaje secundario de <em>{titulo}</em> que acaba de vivir el acontecimiento principal. Máximo 5 frases. Fecha la entrada con el período histórico de la obra.',
       'CCL · Escritura creativa en contexto histórico'],
    ],
    filosofia: [
      ['opinion',
       '<strong>El dilema (2+3 min)</strong><br><em>{titulo}</em> plantea una situación moralmente compleja. 2 minutos de reflexión individual: ¿qué habrías hecho tú en el lugar del protagonista? Después: una persona argumenta a favor de la decisión del personaje, otra en contra.',
       'CPSAA · Argumentación ética y pensamiento crítico'],
      ['visual',
       '<strong>¿Qué preguntaría Sócrates? (5 min)</strong><br>Piensa en el protagonista de <em>{titulo}</em>. Formula la pregunta más incómoda que Sócrates le haría — una que el personaje no pueda responder fácilmente. Escríbela y comparte con el compañero de al lado.',
       'CCL · Mayéutica y diálogo filosófico'],
      ['escritura',
       '<strong>Tesis en 3 frases (5 min)</strong><br>Resume el conflicto filosófico de <em>{titulo}</em> en exactamente 3 frases: (1) el problema, (2) la postura del protagonista, (3) tu propia opinión razonada. No uses más de 3 frases.',
       'CCL · CPSAA · Síntesis argumentativa'],
    ],
    emocional: [
      ['opinion',
       '<strong>El termómetro emocional (5 min)</strong><br>¿Qué emoción domina en <em>{titulo}</em>? Cada persona escribe la suya en un papel sin mostrarlo. A la cuenta de tres, todos la revelan. ¿Hay consenso? Debatid 2 minutos: ¿por qué cada persona eligió la suya?',
       'CPSAA · Identificación y regulación emocional'],
      ['escritura',
       '<strong>Carta al personaje (5 min)</strong><br>Escribe una carta breve al protagonista de <em>{titulo}</em>. Solo tienes 3 frases: una para mostrar que le entiendes, una para preguntarle algo, una para darle un consejo. Sin introducción ni despedida.',
       'CCL · CPSAA · Empatía y escritura expresiva'],
      ['visual',
       '<strong>Línea emocional (5 min)</strong><br>Dibuja en tu cuaderno una línea horizontal. Marca el inicio y el final de <em>{titulo}</em> en los extremos. Después traza cómo crees que va cambiando la emoción del protagonista a lo largo de la historia. Compara con tu compañero.',
       'CPSAA · Representación visual de procesos emocionales'],
    ],
    visual: [
      ['visual',
       '<strong>El encuadre habla (5 min)</strong><br>Imagina la viñeta más importante de <em>{titulo}</em>. Descríbela en voz alta o por escrito: ¿qué tipo de plano usarías (primer plano, plano general…)? ¿Qué parte de la escena quedaría fuera del cuadro? ¿Por qué esa elección?',
       'CCEC · Análisis del lenguaje visual y narrativo'],
      ['opinion',
       '<strong>Sin palabras (5 min)</strong><br>Si quitaras todos los textos de <em>{titulo}</em>, ¿se entendería la historia solo con las imágenes? Debate en parejas: ¿qué se ganaría? ¿qué se perdería? ¿Hay obras donde las imágenes dicen más que las palabras?',
       'CCEC · CCL · Relación texto-imagen en narrativa gráfica'],
      ['escritura',
       '<strong>Rediseña la portada (5 min)</strong><br>Describe en un párrafo cómo rediseñarías la portada de <em>{titulo}</em> para que llegue a personas de tu edad. ¿Qué imagen usarías? ¿Qué colores? ¿Cambiarías el título? Justifica cada decisión.',
       'CCEC · Creación e interpretación de imágenes'],
    ],
    ciencia: [
      ['opinion',
       '<strong>¿Es posible? (2+3 min)</strong><br>El concepto científico de <em>{titulo}</em> — ¿es ciencia real, ciencia futura o ciencia imposible? 2 minutos de investigación mental individual. Después: cada persona defiende su postura con un argumento. Votad al final.',
       'STEM · Pensamiento científico y evaluación de evidencias'],
      ['visual',
       '<strong>El científico critica (5 min)</strong><br>Imagina que un investigador real lee <em>{titulo}</em>. En parejas: listad un error científico probable y un acierto probable que encontraría. Basaos en la descripción. ¿Importa que el manga no sea 100% preciso?',
       'STEM · Pensamiento crítico sobre representaciones científicas'],
      ['escritura',
       '<strong>Dilema ético en 5 frases (5 min)</strong><br>La tecnología o ciencia de <em>{titulo}</em> existe hoy (o podría existir pronto). Escribe 5 frases: 2 argumentos a favor de usarla, 2 en contra, y 1 frase con tu postura personal.',
       'STEM · CPSAA · Ética científica y tecnológica'],
    ],
    genero: [
      ['opinion',
       '<strong>El test de Bechdel (5 min)</strong><br>El test de Bechdel pregunta: ¿hay en la obra dos personajes femeninos que hablen entre sí de algo que no sea un hombre? Debatid si <em>{titulo}</em> lo pasaría. ¿Es este un buen criterio para evaluar una obra? ¿Por qué sí o no?',
       'CSC · Análisis de representación de género en medios'],
      ['escritura',
       '<strong>Intercambio de roles (5 min)</strong><br>Elige al protagonista de <em>{titulo}</em>. Reescribe en 3 frases el arranque de la historia con los géneros de los personajes principales intercambiados. ¿Cambia algo más que el género? ¿Cambiaría la recepción de la obra?',
       'CSC · CPSAA · Perspectiva de género en narrativa'],
      ['visual',
       '<strong>Publicidad de época vs. hoy (5 min)</strong><br>Si <em>{titulo}</em> se publicara hoy, ¿cómo sería su campaña publicitaria comparada con la de su época original? Describid en parejas dos decisiones concretas que cambiarían. ¿Por qué habrían cambiado?',
       'CSC · CCEC · Evolución de representaciones culturales'],
    ],
    lenguas: [
      ['opinion',
       '<strong>Traduce sin diccionario (5 min)</strong><br>El título <em>{titulo}</em> proviene de una cultura muy diferente. En grupos de 3: intentad deducir qué podría significar literalmente, qué connotaciones culturales tiene, y si existe un equivalente en español o en la cultura canaria.',
       'CP · CCL · Mediación lingüística e intercultural'],
      ['escritura',
       '<strong>Préstamo cultural (5 min)</strong><br>El manga como forma artística viajó de Japón al mundo. Escribe 3 frases sobre qué crees que se mantuvo en ese viaje, qué cambió y qué ganó. Luego: ¿conoces otro ejemplo de algo que viajó de una cultura a otra y cambió por el camino?',
       'CP · CCEC · Transferencia e hibridación cultural'],
      ['visual',
       '<strong>Expresión sin traducción (5 min)</strong><br>En <em>{titulo}</em> hay elementos visuales que no necesitan traducción (onomatopeyas gráficas, expresiones faciales exageradas…). En parejas: buscad 3 convenciones visuales del manga que entenderías en cualquier idioma. ¿Por qué funcionan?',
       'CP · CCEC · Lenguaje visual como comunicación universal'],
    ],
    inclusion: [
      ['opinion',
       '<strong>¿Quién falta? (5 min)</strong><br>Piensa en los personajes de <em>{titulo}</em>. ¿Qué tipo de persona no está nunca representada en esta historia? Debatid: ¿importa que las obras de ficción representen a todo el mundo? ¿Cuándo sí y cuándo no?',
       'CSC · Análisis crítico de representación y diversidad'],
      ['escritura',
       '<strong>Barrera invisible (5 min)</strong><br>El protagonista de <em>{titulo}</em> se enfrenta a obstáculos en su contexto. Escribe 3 frases sobre qué barreras encontraría ese mismo personaje si viviera en Las Palmas de Gran Canaria hoy. ¿Serían las mismas o diferentes?',
       'CSC · CPSAA · Transferencia de contexto y empatía'],
      ['visual',
       '<strong>Otro punto de vista (5 min)</strong><br>Cuenta el argumento de <em>{titulo}</em> en 5 frases desde la perspectiva del personaje más secundario o menos visible de la historia. ¿Cambia algo importante? ¿Qué partes de la historia original desaparecen o cobran más importancia?',
       'CCL · CSC · Perspectiva múltiple y empatía narrativa'],
    ],
  };

  // ── Estado ────────────────────────────────────────────────────
  let currentCard  = null;
  let currentIndex = null;

  // ── Abrir modal ───────────────────────────────────────────────
  window.openExpres = function(card) {
    const _opener = document.activeElement;
    currentCard  = card;
    currentIndex = null;
    renderExpres();
    document.getElementById('expresOverlay').classList.add('open');
    document.body.style.overflow = 'hidden';
    FocusTrap.activate(document.getElementById('expresModal'), _opener);
    if (typeof logActivity === 'function') {
      const t = card.querySelector('.cat-title')?.textContent?.trim() || '';
      logActivity('viewed', { title: t, section: 'Actividad exprés' });
    }
  };

  window.closeExpres = function() {
    document.getElementById('expresOverlay').classList.remove('open');
    document.body.style.overflow = '';
    currentCard = null;
    FocusTrap.deactivate();
  };

  // ── Renderizar ────────────────────────────────────────────────
  function renderExpres() {
    if (!currentCard) return;
    const title = currentCard.querySelector('.cat-title')?.textContent?.trim() || '';
    const uso   = (currentCard.getAttribute('data-uso') || '').split(/\s+/)[0] || 'visual';
    const pool  = PLANTILLAS[uso] || PLANTILLAS.visual;

    // Pick next activity (cycle, not repeat consecutive)
    let idx;
    do { idx = Math.floor(Math.random() * pool.length); }
    while (pool.length > 1 && idx === currentIndex);
    currentIndex = idx;

    const [tipo, instrHtml, comp] = pool[idx];
    const tipoData = TIPOS[tipo] || TIPOS.opinion;

    document.getElementById('expresTitleLine').textContent = title;
    const badge = document.getElementById('expresTipoBadge');
    badge.textContent      = tipoData.label;
    badge.style.background = tipoData.color;
    document.getElementById('expresInstrucciones').innerHTML = instrHtml.replace(/\{titulo\}/g, `<em>${title}</em>`);
    document.getElementById('expresComp').textContent = comp;
  }

  // ── Botón regenerar ───────────────────────────────────────────
  document.addEventListener('DOMContentLoaded', function() {
    document.getElementById('expresRegenBtn')?.addEventListener('click', renderExpres);

    // Escape key
    document.addEventListener('keydown', e => {
      if (e.key === 'Escape' && document.getElementById('expresOverlay')?.classList.contains('open')) {
        window.closeExpres();
      }
    });

    // Inject "⚡ Exprés" button into every cat-card-actions
    document.querySelectorAll('.cat-card').forEach(card => {
      const actions = card.querySelector('.cat-card-actions');
      if (!actions || actions.querySelector('.cat-expres-btn')) return;
      const btn = document.createElement('button');
      btn.type      = 'button';
      btn.className = 'cat-expres-btn';
      btn.title     = 'Actividad exprés para el aula (5 min)';
      btn.textContent = '⚡ Exprés';
      btn.onclick   = () => window.openExpres(card);
      // Insert before the OPAC link (which is outside actions), after last button
      actions.appendChild(btn);
    });
  });

})();

// ══════════════════════════════════════════════════════════════════
// PREGUNTAS DETONADORAS POR ERA HISTÓRICA
// ══════════════════════════════════════════════════════════════════
(function() {

  // ── Preguntas por era ─────────────────────────────────────────
  const ERA_QUESTIONS = {
    'Heian': {
      nivel: 'Secundaria · Bachillerato · Universidad',
      preguntas: [
        '¿Por qué el arte japonés más refinado nació en un período de paz aristocrática? ¿Qué condiciones sociales permiten que florezca la cultura?',
        'Las Chōjū-giga muestran animales que se comportan como humanos criticando a la nobleza. ¿Qué tradición artística occidental conoces que use el mismo recurso?'
      ]
    },
    'Kamakura · Muromachi': {
      nivel: 'Secundaria · Bachillerato',
      preguntas: [
        'Japón pasó de una nobleza cortesana a una clase guerrera (samurái) en el poder. ¿Conoces en la historia occidental algún cambio de élite similar?',
        'El bushido establece un código de honor estricto. ¿En qué se parece y en qué se diferencia del código caballeresco europeo medieval?'
      ]
    },
    'Sengoku · Momoyama': {
      nivel: 'Secundaria · Bachillerato',
      preguntas: [
        'El Sengoku es un siglo de guerra civil continua. ¿Qué condiciones políticas explican que un país fragmentado en señoríos rivales acabe unificándose?',
        '¿Por qué crees que la cultura japonesa (teatro Nō, ceremonia del té, jardines zen) alcanzó una refinación extrema justo en un período de violencia máxima?'
      ]
    },
    'Edo': {
      nivel: 'Secundaria · Bachillerato · Universidad',
      preguntas: [
        'Japón cerró sus fronteras al mundo exterior durante más de 200 años (sakoku). ¿Qué consecuencias tuvo ese aislamiento en su desarrollo cultural, tecnológico y económico?',
        'Hokusai publica en 1814 los cuadernos que darán nombre al manga. ¿Por qué una cultura con siglos de arte visual secuencial tarda tanto en crear un término propio para nombrarlo?'
      ]
    },
    'Meiji': {
      nivel: 'Secundaria · Bachillerato',
      preguntas: [
        'Japón pasó en pocas décadas de feudalismo a potencia industrial moderna. ¿Qué pierde y qué gana una sociedad cuando moderniza a marcha forzada?',
        'Los primeros manga de la era Meiji copiaron técnicas de la caricatura occidental. ¿Es copiar una forma de resistencia cultural o de colonización cultural? ¿Puede ser las dos cosas?'
      ]
    },
    'Taishō': {
      nivel: 'Secundaria · Bachillerato',
      preguntas: [
        'La era Taishō fue la más democrática y cosmopolita del Japón premoderno. ¿Por qué duró tan poco? ¿Qué factores históricos pueden truncar un período liberal?',
        'El manga cómico de esta época mezcla humor absurdo con crítica social. ¿Qué otras formas artísticas conoces que usen el humor para decir verdades incómodas?'
      ]
    },
    'Shōwa': {
      nivel: 'Secundaria · Bachillerato · Universidad',
      preguntas: [
        'Tezuka sobrevivió los bombardeos de Osaka y en 1952 crea a Astroboy, un niño-robot símbolo de esperanza. ¿Cómo puede el trauma colectivo transformarse en arte que mira al futuro?',
        'El manga de posguerra nació en revistas de alquiler para niños pobres que no podían comprarlas. ¿Qué relación existe entre la precariedad económica y la explosión de una forma artística popular?'
      ]
    },
    'Heisei': {
      nivel: 'ESO · Bachillerato · Universidad',
      preguntas: [
        'El manga Heisei tematiza el miedo a la tecnología, la identidad líquida y el fin del mundo. ¿En qué medida esos miedos de los años 90 japoneses siguen siendo los nuestros hoy?',
        'Japón exportó su cultura pop masivamente durante el Heisei (anime, manga, videojuegos). ¿Es eso soft power? ¿En qué se diferencia de la exportación cultural que hacen EE. UU. o Europa?'
      ]
    },
    'Reiwa': {
      nivel: 'ESO · Bachillerato · Universidad',
      preguntas: [
        'El manga Reiwa representa protagonistas que buscan "vivir despacio" (日常系, nichijō-kei). ¿Qué dice eso de la sociedad japonesa actual? ¿Resonaría en el alumnado canario?',
        'Por primera vez en su historia, el manga japonés tiene más lectoras que lectores. ¿Qué transforma una industria cultural cuando cambia quién la consume?'
      ]
    }
  };

  // ── Panel activo (solo uno a la vez) ─────────────────────────
  let activePanel = null;
  let activeBtn   = null;

  function closeActive() {
    if (!activePanel) return;
    activePanel.classList.remove('open');
    if (activeBtn) activeBtn.classList.remove('active');
    activePanel = null;
    activeBtn   = null;
  }

  // ── Inyectar botón + panel en cada .bar ───────────────────────
  function initEraQuestions() {
    document.querySelectorAll('.bar').forEach(bar => {
      const nameEl = bar.querySelector('.era-name');
      if (!nameEl) return;
      const eraName = nameEl.textContent.trim();
      const data    = ERA_QUESTIONS[eraName];
      if (!data) return;

      // Botón ?
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'era-q-btn';
      btn.textContent = '?';
      btn.setAttribute('aria-label', `Pregunta detonadora: ${eraName}`);
      btn.setAttribute('title', 'Pregunta detonadora para el aula');

      // Panel — appended to body so it escapes overflow:hidden scroll
      const panel = document.createElement('div');
      panel.className = 'era-q-panel';
      panel.setAttribute('role', 'dialog');
      panel.innerHTML = `
        <span class="era-q-label">✦ Pregunta detonadora · ${eraName}</span>
        <span class="era-q-nivel">${data.nivel}</span>
        <ul class="era-q-list">
          ${data.preguntas.map(q => `<li>${q}</li>`).join('')}
        </ul>`;
      document.body.appendChild(panel);

      function positionPanel() {
        const r = btn.getBoundingClientRect();
        const pw = 260;
        panel.style.width = pw + 'px';
        panel.style.display = 'block';
        const ph = panel.offsetHeight;
        panel.style.display = '';

        // Try above first, fall back to below
        let top, left;
        if (r.top - ph - 10 > 60) {
          top = r.top - ph - 10;
        } else {
          top = r.bottom + 10;
          // Flip arrow to point up
          panel.classList.add('arrow-down-off');
        }
        left = r.left + r.width / 2 - pw / 2;
        // Keep within viewport
        left = Math.max(8, Math.min(left, window.innerWidth - pw - 8));
        top  = Math.max(8, top);

        panel.style.top  = top + 'px';
        panel.style.left = left + 'px';
      }

      btn.onclick = function(e) {
        e.stopPropagation();
        if (activePanel === panel) { closeActive(); return; }
        closeActive();
        positionPanel();
        panel.classList.add('open');
        btn.classList.add('active');
        activePanel = panel;
        activeBtn   = btn;
      };

      panel.addEventListener('click', e => e.stopPropagation());
      bar.appendChild(btn);
    });

    // Close on click outside
    document.addEventListener('click', closeActive);
    document.addEventListener('keydown', e => { if (e.key === 'Escape') closeActive(); });
    // Reposition on scroll
    document.getElementById('sc')?.addEventListener('scroll', () => { if (activePanel) closeActive(); });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initEraQuestions);
  } else {
    initEraQuestions();
  }

})();

