  'master keaton  re master'                                   : 'Master Keaton',
  'solanin  integral'                                          : 'Solanin',
  'planetes integral'                                          : 'Planetes',
  'el lobo solitario y su cachorro'                            : 'Lobo solitario y su cachorro',
  'devorar la tierra'                                          : 'Devorar la tierra',
