/**
 * Genera una rúbrica LOMLOE completa en HTML sin necesidad de IA ni red.
 * Se enriquece con el nombre del título para contextualizar los criterios.
 *
 * @param {string}   titulo - Nombre del título de manga
 * @param {string}   etapa  - Etapa educativa
 * @param {string[]} comps  - Códigos de competencia clave ['CCL', 'CPSAA', …]
 * @returns {string} HTML completo de la rúbrica
 */
function generarRubricaLocal(titulo, etapa, comps) {
  if (!titulo || !etapa || !comps.length) {
    return '<p class="rubrica-placeholder">Completa el título, la etapa y al menos una competencia.</p>';
  }

  const filas = comps.flatMap(comp => {
    const def = RUBRICA_CRITERIOS[comp];
    if (!def) return [];
    return def.criterios.map(c => `
      <tr>
        <td class="rubrica-td-comp">
          <strong>${def.nombre}</strong><br>
          <em>${c.dimension}</em>
        </td>
        <td class="rubrica-td-n1">${c.inicial}</td>
        <td class="rubrica-td-n2">${c.proceso}</td>
        <td class="rubrica-td-n3">${c.alcanzado}</td>
        <td class="rubrica-td-n4">${c.excelente}</td>
      </tr>`);
  }).join('');

  if (!filas) return '<p class="rubrica-placeholder">Las competencias seleccionadas no tienen criterios disponibles.</p>';

  return `
    <div class="rubrica-local-wrap">
      <h3 class="rubrica-local-title">
        Rúbrica de evaluación — <em>${titulo}</em>
        <span class="rubrica-local-etapa">${etapa}</span>
      </h3>
      <p class="rubrica-local-src">
        Criterios adaptados de
        <a href="https://www.boe.es/buscar/act.php?id=BOE-A-2022-5146" target="_blank"
           rel="noopener noreferrer">RD 217/2022</a> y
        <a href="https://www.boe.es/buscar/act.php?id=BOE-A-2022-3296" target="_blank"
           rel="noopener noreferrer">RD 157/2022</a> (LOMLOE).
        Generada sin IA — adapta los descriptores al contexto de tu aula.
      </p>
      <div class="rubrica-local-scroll">
        <table class="rubrica-local-table" role="table">
          <thead>
            <tr>
              <th scope="col" class="rubrica-th-comp">Competencia / Dimensión</th>
              <th scope="col" class="rubrica-th-n1">Inicial (1)</th>
              <th scope="col" class="rubrica-th-n2">En proceso (2)</th>
              <th scope="col" class="rubrica-th-n3">Alcanzado (3)</th>
              <th scope="col" class="rubrica-th-n4">Excelente (4)</th>
            </tr>
          </thead>
          <tbody>${filas}</tbody>
        </table>
      </div>
      <p class="rubrica-local-note">
        ⚠ Esta rúbrica es un punto de partida. Adapta los descriptores al contexto concreto
        de tu aula y a los criterios de evaluación de tu programación antes de compartirla
        con el alumnado.
      </p>
    </div>`;
}

// ── Integración con el modal de rúbricas existente ───────────────
// Añadir botón «Sin IA» junto al botón principal y activar fallback por timeout.
document.addEventListener('DOMContentLoaded', function() {
  const genBtn = document.getElementById('rubricaGenBtn');
  if (!genBtn) return;

  // Insertar botón «Generar sin IA» justo después del botón principal
  const sinIaBtn = document.createElement('button');
  sinIaBtn.type = 'button';
  sinIaBtn.id   = 'rubricaLocalBtn';
  sinIaBtn.className = 'rubrica-gen-btn rubrica-local-btn';
  sinIaBtn.textContent = '⊡ Sin IA (offline)';
  sinIaBtn.title = 'Genera la rúbrica con plantillas locales, sin necesidad de red ni API key';
  sinIaBtn.addEventListener('click', () => {
    const titulo = (document.getElementById('rubricaTitulo')?.value || '').trim();
    const etapa  = document.getElementById('rubricaNivel')?.value || 'ESO';
    const comps  = [...document.querySelectorAll('#rubricaCompChecks input:checked')]
                    .map(cb => cb.value);
    const body   = document.getElementById('rubricaBody');
    if (body) body.innerHTML = generarRubricaLocal(titulo, etapa, comps);
  });
  genBtn.insertAdjacentElement('afterend', sinIaBtn);

  // Fallback automático: si la IA no responde en 14s, mostrar rúbrica local
  const _origGenerarRubrica = window.generarRubrica || function(){};
  window.generarRubrica = async function() {
    const titulo = (document.getElementById('rubricaTitulo')?.value || '').trim();
    const etapa  = document.getElementById('rubricaNivel')?.value || 'ESO';
    const comps  = [...document.querySelectorAll('#rubricaCompChecks input:checked')]
                    .map(cb => cb.value);
    const body   = document.getElementById('rubricaBody');

    // Iniciar temporizador de fallback
    const fallbackTimer = setTimeout(() => {
      if (body && body.querySelector('.rubrica-placeholder, .rubrica-loading')) {
        body.innerHTML = generarRubricaLocal(titulo, etapa, comps) +
          '<p class="rubrica-fallback-note">⚠ La generación con IA tardó demasiado. Se usó la plantilla local.</p>';
      }
    }, 14000);

    try {
      await _origGenerarRubrica();
    } finally {
      clearTimeout(fallbackTimer);
    }
  };
});


