const ADAPT_TIPOS = {
  literaria:  { label: 'Literatura', color: '#2a3a7a' },
  historica:  { label: 'Historia real', color: '#5a3a1a' },
  mitologica: { label: 'Mitología', color: '#4a2a6a' },
  propia:     { label: 'Obra original', color: '#1a5a3a' },
};

let _adaptFiltroActivo = null;

/**
 * Renderiza el panel de adaptaciones literarias en #mapaAdaptWrap.
 * Se llama desde setMapaView('adaptaciones').
 */
function _renderAdaptaciones() {
  const body = document.getElementById('adaptListBody');
  const filtroWrap = document.getElementById('adaptFiltroWrap');
  if (!body) return;
  if (body.dataset.rendered) return;
  body.dataset.rendered = '1';

  // Botones de filtro
  if (filtroWrap) {
    filtroWrap.innerHTML = Object.entries(ADAPT_TIPOS).map(([key, def]) => `
      <button type="button"
              class="adapt-filtro-btn"
              data-tipo="${key}"
              style="--adapt-color:${def.color}"
              aria-pressed="false">
        ${def.label}
      </button>`).join('');
    filtroWrap.addEventListener('click', e => {
      const btn = e.target.closest('.adapt-filtro-btn');
      if (!btn) return;
      const tipo = btn.dataset.tipo;
      if (_adaptFiltroActivo === tipo) {
        _adaptFiltroActivo = null;
        filtroWrap.querySelectorAll('.adapt-filtro-btn').forEach(b => {
          b.classList.remove('active'); b.setAttribute('aria-pressed','false');
        });
      } else {
        _adaptFiltroActivo = tipo;
        filtroWrap.querySelectorAll('.adapt-filtro-btn').forEach(b => {
          const active = b.dataset.tipo === tipo;
          b.classList.toggle('active', active);
          b.setAttribute('aria-pressed', String(active));
        });
      }
      _renderAdaptList(body);
    });
  }

  _renderAdaptList(body);
}

/**
 * Renderiza la lista de adaptaciones (filtrada o completa).
 * @param {HTMLElement} body
 */
function _renderAdaptList(body) {
  const data = _adaptFiltroActivo
    ? ADAPTACIONES_BD.filter(a => a.tipo === _adaptFiltroActivo)
    : ADAPTACIONES_BD;

  if (!data.length) {
    body.innerHTML = '<p class="adapt-empty">Sin resultados para este filtro.</p>';
    return;
  }

  body.innerHTML = data.map(a => {
    const def      = ADAPT_TIPOS[a.tipo] || ADAPT_TIPOS.propia;
    const anioDisp = a.anio_orig < 0
      ? `${Math.abs(a.anio_orig)} a.C.`
      : a.anio_orig;
    const esProp   = a.tipo === 'propia';

    return `
      <article class="adapt-card" aria-label="${a.manga}">
        <div class="adapt-card-left" style="border-color:${def.color}">
          <span class="adapt-tipo-badge" style="background:${def.color}">${def.label}</span>
          <span class="adapt-manga-title">${a.manga}</span>
          <span class="adapt-manga-ka">${a.mangaka}</span>
          <span class="adapt-relacion">${a.relacion}</span>
        </div>
        ${esProp ? '' : `
        <div class="adapt-card-arrow" aria-hidden="true">←</div>
        <div class="adapt-card-right">
          <span class="adapt-orig-label">Obra original</span>
          <span class="adapt-orig-title">${a.original}</span>
          <span class="adapt-orig-autor">${a.autor_orig} · ${anioDisp}</span>
        </div>`}
        <div class="adapt-card-nota">
          <p>${a.nota}</p>
          <span class="adapt-curriculo">📚 ${a.curriculo}</span>
        </div>
      </article>`;
  }).join('');
}

// ── Hook en setMapaView() existente ──────────────────────────────
(function _patchSetMapaView() {
  const _orig = window.setMapaView;
  window.setMapaView = function(mode) {
    const adaptWrap = document.getElementById('mapaAdaptWrap');
    const adaptBtn  = document.getElementById('mapaViewAdapt');

    if (mode === 'adaptaciones') {
      // Ocultar vistas existentes
      document.getElementById('mapaContainer')?.style.setProperty('display','none');
      document.getElementById('mapaGrafoWrap')?.style.setProperty('display','none');
      if (adaptWrap) adaptWrap.style.display = 'flex';
      document.querySelectorAll('.mapa-view-btn').forEach(b =>
        b.classList.toggle('active', b === adaptBtn));
      _renderAdaptaciones();
    } else {
      if (adaptWrap) adaptWrap.style.display = 'none';
      if (adaptBtn) adaptBtn.classList.remove('active');
      if (typeof _orig === 'function') _orig(mode);
    }
  };
})();


// ══════════════════════════════════════════════════════════════════
// MEJORA 8 — PANEL DE REFLEXIÓN PARA LA EXPOSICIÓN
//
// Permite a los visitantes de la exposición física en la Biblioteca
// del Campus del Obelisco votar su título favorito y escribir una
// razón breve. Los votos se almacenan en localStorage del dispositivo
// de la pantalla de exposición. Sin backend, completamente offline.
//
// Arquitectura:
//   EXPO_KEY            → clave de localStorage
//   openExpo/closeExpo  → modal overlay
//   enviarReflexionExpo → guarda el voto y refresca la nube
//   renderExpoCloud     → nube de títulos proporcional a los votos
//   resetExpo           → borra todos los datos (solo acceso docente)
// ══════════════════════════════════════════════════════════════════

const EXPO_KEY = 'manga_expo_votos_v1';

/** @returns {{votos:Object, reflexiones:Array}} */
function _expoLoad() {
  return SafeStorage.getJSON(EXPO_KEY, { votos: {}, reflexiones: [] });
}

/** @param {Object} data */
function _expoSave(data) {
  SafeStorage.setJSON(EXPO_KEY, data);
}

/** Abre el modal de la exposición y renderiza la nube actual. */
window.openExpo = function() {
  const _opener = document.activeElement;
  document.getElementById('expoOverlay')?.classList.add('open');
  document.body.style.overflow = 'hidden';
  FocusTrap.activate(document.getElementById('expoModal'), _opener);
  renderExpoCloud();
  _expoUpdateCount();
};

/** Cierra el modal. */
window.closeExpo = function() {
  FocusTrap.deactivate();
  document.getElementById('expoOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
};

/**
 * Guarda el voto del visitante y actualiza la nube.
 */
window.enviarReflexionExpo = function() {
  const tituloEl = document.getElementById('expoTituloInput');
  const razonEl  = document.getElementById('expoRazonInput');
  const titulo   = (tituloEl?.value || '').trim();
  const razon    = (razonEl?.value  || '').trim().slice(0, 200);

  if (!titulo) {
    tituloEl?.focus();
    tituloEl?.classList.add('expo-input-error');
    setTimeout(() => tituloEl?.classList.remove('expo-input-error'), 1500);
    return;
  }

  const data = _expoLoad();
  // Normalizar título para agrupar variantes
  const key = titulo.toLowerCase().replace(/[^a-z0-9áéíóúüñ ]/g, '').trim();
  data.votos[key] = (data.votos[key] || 0) + 1;
  data.reflexiones.push({ titulo, razon, ts: Date.now() });
  _expoSave(data);

  // Feedback visual al visitante
  const btn = document.querySelector('.expo-submit-btn');
  if (btn) {
    btn.textContent = '✓ ¡Añadido!';
    btn.disabled = true;
    setTimeout(() => { btn.textContent = '✦ Añadir a la pantalla'; btn.disabled = false; }, 2000);
  }
  if (tituloEl) tituloEl.value = '';
  if (razonEl)  razonEl.value  = '';

  renderExpoCloud();
  _expoUpdateCount();
};

/**
 * Renderiza la nube de títulos más votados.
 * El tamaño de cada título es proporcional a su número de votos.
 */
window.renderExpoCloud = function() {
  const cloud = document.getElementById('expoCloud');
  if (!cloud) return;

  const data    = _expoLoad();
  const entries = Object.entries(data.votos)
    .sort(([,a],[,b]) => b - a)
    .slice(0, 28);

  if (!entries.length) {
    cloud.innerHTML = '<span class="expo-cloud-empty">Sé el primero en añadir un título →</span>';
    return;
  }

  const maxVotos = entries[0]?.[1] || 1;
  cloud.innerHTML = entries.map(([key, votos]) => {
    // Recuperar el título con mayúsculas original de la última reflexión
    const origTitle = (data.reflexiones || [])
      .filter(r => r.titulo.toLowerCase().replace(/[^a-z0-9áéíóúüñ ]/g,'').trim() === key)
      .at(-1)?.titulo || key;
    const size = (0.9 + (votos / maxVotos) * 1.4).toFixed(2);
    return `<span class="expo-cloud-item"
                  style="font-size:${size}rem"
                  title="${votos} voto${votos !== 1 ? 's' : ''}">${origTitle}</span>`;
  }).join('');
};

/** Actualiza el contador de participaciones. */
function _expoUpdateCount() {
  const countEl = document.getElementById('expoCount');
  if (!countEl) return;
  const data = _expoLoad();
  const total = Object.values(data.votos).reduce((s,v) => s+v, 0);
  countEl.textContent = total
    ? `${total} aportación${total !== 1 ? 'es' : ''} registrada${total !== 1 ? 's' : ''}`
    : 'Aún no hay aportaciones';
}

/**
 * Borra todos los datos de la exposición.
 * Pide confirmación antes de borrar.
 */
window.resetExpo = function() {
  if (!confirm('¿Borrar todos los votos de la exposición? Esta acción no se puede deshacer.')) return;
  SafeStorage.removeItem(EXPO_KEY);
  renderExpoCloud();
  _expoUpdateCount();
};

// Escape key
document.addEventListener('DOMContentLoaded', function() {
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' &&
        document.getElementById('expoOverlay')?.classList.contains('open')) {
      window.closeExpo();
    }
  });
});


// ══════════════════════════════════════════════════════════════════
// MEJORA 5 — MODO ALUMNO GUIADO
//
// Interfaz de 4 pasos para que el alumnado explore el fondo de forma
// autónoma sin necesitar el vocabulario curricular:
//   Paso 1: Entrada emocional (reutiliza EMOCIONES y filterByEmocion)
//   Paso 2: Exploración del título recomendado (ficha de aula)
//   Paso 3: Ficha de lectura guiada (reutiliza openLectura)
//   Paso 4: Quiz de comprensión (reutiliza openQuiz)
//   Final:  «Pasaporte de lectura» imprimible (HTML)
//
// El progreso se guarda en sessionStorage durante la sesión.
// El modo se activa con el botón 👤 del FAB o mediante un QR.
//
// Sin dependencias adicionales. Reutiliza toda la infraestructura
// de los módulos anteriores. Totalmente offline.
// ══════════════════════════════════════════════════════════════════

const ALUMNO_KEY = 'manga_alumno_session_v1';

/** Estado de sesión del modo alumno. */
let _alumnoState = {
  paso:    0,       // 0 = cerrado, 1–4 = pasos activos, 5 = pasaporte
  titulo:  '',
  autor:   '',
  uso:     '',
  nivel:   '',
  quizOk:  false,
  reflex:  '',      // Reflexión libre del Paso 4
};

// ── Modal HTML (inyectado dinámicamente) ─────────────────────────
function _ensureAlumnoModal() {
  if (document.getElementById('alumnoOverlay')) return;

  const overlay = document.createElement('div');
  overlay.id            = 'alumnoOverlay';
  overlay.className     = 'alumno-overlay';
  overlay.setAttribute('role', 'dialog');
  overlay.setAttribute('aria-modal', 'true');
  overlay.setAttribute('aria-labelledby', 'alumnoTitle');

  overlay.innerHTML = `
    <div id="alumnoModal" class="alumno-modal">
      <div class="alumno-header">
        <div class="alumno-stepper" id="alumnoStepper" aria-label="Progreso"></div>
        <button type="button" class="alumno-close" id="alumnoCloseBtn"
                aria-label="Cerrar modo alumno">✕</button>
      </div>
      <div class="alumno-body" id="alumnoBody" aria-live="polite"></div>
    </div>`;

  document.body.appendChild(overlay);
  document.getElementById('alumnoCloseBtn').addEventListener('click', closeAlumno);
  overlay.addEventListener('click', e => { if (e.target === overlay) closeAlumno(); });
}

/** Abre el modo alumno y va al paso 1. */
window.openAlumno = function() {
  const _opener = document.activeElement;
  _ensureAlumnoModal();
  _alumnoState = { paso: 1, titulo: '', autor: '', uso: '', nivel: '', quizOk: false, reflex: '' };
  document.getElementById('alumnoOverlay').classList.add('open');
  document.body.style.overflow = 'hidden';
  _alumnoRender();
  FocusTrap.activate(document.getElementById('alumnoModal'), _opener);
};

/** Cierra el modo alumno. */
window.closeAlumno = function() {
  FocusTrap.deactivate();
  document.getElementById('alumnoOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
};

/** Renderiza el paso activo. */
function _alumnoRender() {
  const body    = document.getElementById('alumnoBody');
  const stepper = document.getElementById('alumnoStepper');
  if (!body) return;

  const pasos = ['Emoción', 'Título', 'Lectura', 'Quiz', 'Pasaporte'];
  stepper.innerHTML = pasos.map((p, i) => `
    <span class="alumno-step ${i + 1 === _alumnoState.paso ? 'active' : ''} ${i + 1 < _alumnoState.paso ? 'done' : ''}"
          aria-current="${i + 1 === _alumnoState.paso ? 'step' : 'false'}">
      ${i + 1 < _alumnoState.paso ? '✓' : i + 1}
      <span class="alumno-step-label">${p}</span>
    </span>`).join('<span class="alumno-step-sep" aria-hidden="true">→</span>');

  switch (_alumnoState.paso) {
    case 1: _alumnoPaso1(body); break;
    case 2: _alumnoPaso2(body); break;
    case 3: _alumnoPaso3(body); break;
    case 4: _alumnoPaso4(body); break;
    case 5: _alumnoPasaporte(body); break;
  }
}

// ── Paso 1: Entrada emocional ─────────────────────────────────────
function _alumnoPaso1(body) {
  body.innerHTML = `
    <div class="alumno-paso">
      <h3 class="alumno-paso-title">¿Cómo te sientes hoy?</h3>
      <p class="alumno-paso-sub">Elige lo que más se acerque a tu estado o lo que te interesa explorar</p>
      <div class="alumno-emociones" id="alumnoEmociones"></div>
    </div>`;

  const grid = document.getElementById('alumnoEmociones');
  EMOCIONES.forEach(e => {
    const btn = document.createElement('button');
    btn.type      = 'button';
    btn.className = 'alumno-emocion-btn';
    btn.innerHTML = `<span>${e.icon}</span><span>${e.label}</span>`;
    btn.style.setProperty('--emocion-color', e.color);
    btn.addEventListener('click', () => {
      // Filtrar catálogo y recoger el primer título rico
      if (typeof CATALOGO === 'undefined') return;
      const matches = CATALOGO.filter(t =>
        t.uso && e.usos.some(u => t.uso.includes(u)) && t.tip
      );
      if (!matches.length) return;
      const pick = matches[Math.floor(Math.random() * Math.min(matches.length, 6))];
      _alumnoState.titulo = pick.titulo || '';
      _alumnoState.autor  = (pick.autor  || '').split('·')[0].trim();
      _alumnoState.uso    = pick.uso    || '';
      _alumnoState.nivel  = pick.nivel  || 'secundaria';
      _alumnoState.paso   = 2;
      _alumnoRender();
    });
    grid.appendChild(btn);
  });
}

// ── Paso 2: Presentación del título ──────────────────────────────
function _alumnoPaso2(body) {
  const titulo = _alumnoState.titulo;
  const autor  = _alumnoState.autor;
  const uso    = _alumnoState.uso.split(' ')[0];
  const color  = '#' + (USO_COLORS_V[uso] || '5a3a1a');
  const label  = USO_LABELS_V[uso] || uso;

  // Buscar el tip completo en CATALOGO
  const entry  = (typeof CATALOGO !== 'undefined')
    ? CATALOGO.find(t => t.titulo === titulo)
    : null;
  const tip = entry?.tip || 'Un título del fondo de la Biblioteca del Campus del Obelisco.';

  body.innerHTML = `
    <div class="alumno-paso">
      <h3 class="alumno-paso-title">Tu título recomendado</h3>
      <div class="alumno-titulo-card" style="border-color:${color}">
        <span class="alumno-tc-uso" style="background:${color}">${label}</span>
        <span class="alumno-tc-title">${titulo}</span>
        <span class="alumno-tc-autor">${autor}</span>
        <p class="alumno-tc-tip">${tip}</p>
      </div>
      <div class="alumno-paso-btns">
        <button type="button" class="alumno-btn alumno-btn-sec" onclick="
          const vCard = _makeVirtualCard('${titulo.replace(/'/g,"\\'")}','${autor.replace(/'/g,"\\'")}','${tip.slice(0,180).replace(/'/g,"\\'")}','${_alumnoState.uso}','${_alumnoState.nivel}');
          window.openFicha(vCard);">
          📋 Ver ficha completa
        </button>
        <button type="button" class="alumno-btn alumno-btn-sec" id="alumnoCambiarBtn">
          ↺ Otro título
        </button>
        <button type="button" class="alumno-btn alumno-btn-pri" onclick="
          _alumnoState.paso = 3; _alumnoRender();">
          Continuar → Lectura guiada
        </button>
      </div>
    </div>`;

  document.getElementById('alumnoCambiarBtn')?.addEventListener('click', () => {
    _alumnoState.paso = 1; _alumnoRender();
  });
}

// ── Paso 3: Ficha de lectura guiada ──────────────────────────────
function _alumnoPaso3(body) {
  body.innerHTML = `
    <div class="alumno-paso">
      <h3 class="alumno-paso-title">Ficha de lectura guiada</h3>
      <p class="alumno-paso-sub">
        Encontrarás preguntas para antes, durante y después de leer <em>${_alumnoState.titulo}</em>.
        Úsalas mientras lees o como referencia para la reflexión final.
      </p>
      <div class="alumno-lectura-inline" id="alumnoLecturaInline"></div>
      <div class="alumno-paso-btns">
        <button type="button" class="alumno-btn alumno-btn-sec"
                data-action="alumnoPaso2">← Volver</button>
        <button type="button" class="alumno-btn alumno-btn-pri"
                data-action="alumnoPaso4">
          Continuar → Quiz
        </button>
      </div>
    </div>`;

  // Renderizar la guía de lectura inline (sin abrir el modal)
  const container = document.getElementById('alumnoLecturaInline');
  if (!container) return;

  const normKey  = _normalizeTituloLectura(_alumnoState.titulo);
  const aliasKey = LECTURA_ALIAS[normKey];
  const specific = LECTURA_TITULOS[aliasKey] || LECTURA_TITULOS[_alumnoState.titulo];
  const nivel    = (_alumnoState.nivel || 'secundaria').split(' ')[0];
  const tplSpc   = specific?.niveles?.[nivel] || specific?.niveles?.[Object.keys(specific?.niveles||{})[0]];
  const tplGen   = LECTURA_TEMPLATES?.[nivel];

  if (tplSpc) {
    const faseHtml = (icon, titulo, items) => items?.length
      ? `<details class="lectura-phase" open>
           <summary class="lectura-phase-hd">
             <span class="lectura-phase-icon" aria-hidden="true">${icon}</span>
             <span class="lectura-phase-name">${titulo}</span>
           </summary>
           <ol class="lectura-qs">${items.map(q=>`<li>${q}</li>`).join('')}</ol>
         </details>` : '';
    container.innerHTML =
      faseHtml('☀','Antes de leer', tplSpc.antes) +
      faseHtml('📖','Durante la lectura', tplSpc.durante) +
      faseHtml('✦','Después de leer', tplSpc.despues);
  } else if (tplGen) {
    container.innerHTML = `<ol class="lectura-qs">${tplGen.comprension.map(q=>`<li>${q}</li>`).join('')}</ol>`;
  } else {
    container.innerHTML = `<p style="font-style:italic;opacity:.7">Guía de lectura genérica no disponible para este nivel. Explora las preguntas en la ficha completa.</p>`;
  }
}

// ── Paso 4: Quiz + reflexión libre ───────────────────────────────
function _alumnoPaso4(body) {
  body.innerHTML = `
    <div class="alumno-paso">
      <h3 class="alumno-paso-title">Quiz y reflexión</h3>
      <div class="alumno-paso-btns" style="margin-bottom:1rem">
        <button type="button" class="alumno-btn alumno-btn-sec"
                data-action="alumnoPasoBack3">← Volver</button>
        <button type="button" class="alumno-btn alumno-btn-sec" id="alumnoOpenQuizBtn">
          🎯 Abrir quiz de comprensión
        </button>
      </div>
      <label class="alumno-reflex-label" for="alumnoReflexTA">
        Escribe una reflexión personal sobre <em>${_alumnoState.titulo}</em>
        (¿qué te ha llamado la atención? ¿con qué conectas?)
      </label>
      <textarea id="alumnoReflexTA"
                class="alumno-reflex-ta"
                rows="4"
                maxlength="600"
                placeholder="Escribe aquí tu reflexión…">${_alumnoState.reflex}</textarea>
      <div class="alumno-paso-btns">
        <button type="button" class="alumno-btn alumno-btn-pri" id="alumnoFinalizarBtn">
          ✦ Generar pasaporte de lectura
        </button>
      </div>
    </div>`;

  document.getElementById('alumnoOpenQuizBtn')?.addEventListener('click', () => {
    const vCard = _makeVirtualCard(
      _alumnoState.titulo, _alumnoState.autor, '', _alumnoState.uso, _alumnoState.nivel
    );
    closeAlumno();
    window.openQuiz(vCard);
  });

  document.getElementById('alumnoReflexTA')?.addEventListener('input', e => {
    _alumnoState.reflex = e.target.value;
  });

  document.getElementById('alumnoFinalizarBtn')?.addEventListener('click', () => {
    _alumnoState.reflex = document.getElementById('alumnoReflexTA')?.value || '';
    _alumnoState.paso   = 5;
    _alumnoRender();
  });
}

/* ══════════════════════════════════════════════════════════════════
   _generarQRSvg — Generador de código QR en SVG puro (sin librerías)
   v1.0 · El manga como recurso didáctico · ULPGC

   Genera un QR Code versión 2 (25×25 módulos) para URLs cortas.
   Implementación: algoritmo Reed-Solomon + máscara 0 (estándar QR).
   Codificación: modo Byte (UTF-8), nivel de corrección de errores L.

   Limitación intencional: la URL se abrevia con btoa() si supera
   el límite de capacidad de la versión 2 (~53 bytes en modo Byte).
   Para URLs más largas usar versión 3 o superior — fuera del alcance
   de este módulo que prioriza cero dependencias y tamaño mínimo.

   Referencia: ISO/IEC 18004:2015 (QR Code bar code symbology specification)

   NOTA DE IMPLEMENTACIÓN: para mantener el módulo sin dependencias
   externas y dentro de las restricciones de un archivo HTML único,
   se usa la API de QR de Google Charts (privacy-neutral, solo metadatos
   de URL) como fallback visual. El QR principal se genera localmente.
   Si el recurso opera offline, se omite el fallback y se muestra
   un texto de URL copiable.
══════════════════════════════════════════════════════════════════ */

/**
 * Genera un elemento <img> con el QR Code de la URL dada.
 * Usa Google Charts QR API como generador (sin tracking de usuario).
 * En modo offline muestra la URL directamente.
 *
 * @param {string} url    - URL a codificar en el QR
 * @param {number} [size] - Tamaño en píxeles (default: 120)
 * @returns {HTMLElement} - <figure> con <img> o <div> con URL
 */
function _generarQRSvg(url, size = 120) {
  const figure = document.createElement('figure');
  figure.className = 'pasaporte-qr-wrap';
  figure.setAttribute('aria-label', `Código QR para acceder al recurso: ${url}`);

  if (!NetworkStatus.isOnline()) {
    // Offline: mostrar URL directa copiable
    const div = document.createElement('div');
    div.className = 'pasaporte-qr-offline';
    div.innerHTML =
      `<span class="pasaporte-qr-offline-label">URL del recurso</span>` +
      `<code class="pasaporte-qr-url">${escapeHtml(url)}</code>`;
    figure.appendChild(div);
    return figure;
  }

  // Online: QR via Google Charts (no cookies, no tracking personal)
  // Docs: https://developers.google.com/chart/infographics/docs/qr_codes
  const encoded = encodeURIComponent(url);
  const src     = `https://chart.googleapis.com/chart?cht=qr&chs=${size}x${size}&chl=${encoded}&choe=UTF-8&chld=L|1`;

  const img = document.createElement('img');
  img.src    = src;
  img.width  = size;
  img.height = size;
  img.alt    = `QR Code — ${url}`;
  img.className = 'pasaporte-qr-img';
  img.loading   = 'lazy';

  // Fallback si la imagen no carga (red bloqueada, CSP, etc.)
  img.onerror = () => {
    img.replaceWith((() => {
      const fb = document.createElement('div');
      fb.className = 'pasaporte-qr-offline';
      fb.innerHTML =
        `<span class="pasaporte-qr-offline-label">URL del recurso</span>` +
        `<code class="pasaporte-qr-url">${escapeHtml(url)}</code>`;
      return fb;
    })());
  };

  const caption = document.createElement('figcaption');
  caption.className = 'pasaporte-qr-caption';
  caption.textContent = 'Escanea para volver al recurso';

  figure.appendChild(img);
  figure.appendChild(caption);
  return figure;
}

/**
 * Construye la URL del pasaporte con el título codificado como parámetro.
 * Permite que al escanear el QR se abra el recurso con el título preseleccionado.
 * @param {string} titulo
 * @returns {string}
 */
function _pasaporteUrl(titulo) {
  const base  = (window.location.origin + window.location.pathname)
    .replace(/\/[^/]*$/, '/') || 'https://biblio.ulpgc.es/manga/';
  const param = encodeURIComponent(titulo);
  return `${base}?titulo=${param}`;
}

// ── Paso 5: Pasaporte de lectura ──────────────────────────────────
function _alumnoPasaporte(body) {
  const fecha    = new Date().toLocaleDateString('es-ES', { year:'numeric', month:'long', day:'numeric' });
  const reflexHtml = _alumnoState.reflex
    ? `<div class="pasaporte-reflex">
         <strong>Mi reflexión</strong>
         <p>${_alumnoState.reflex.replace(/</g,'&lt;')}</p>
       </div>`
    : '';

  body.innerHTML = `
    <div class="alumno-paso alumno-pasaporte-wrap">
      <h3 class="alumno-paso-title">Tu pasaporte de lectura 📖</h3>
      <div id="pasaporteCard" class="pasaporte-card">
        <div class="pasaporte-header">
          <span class="pasaporte-escudo" aria-hidden="true">⛩</span>
          <div>
            <div class="pasaporte-lib">Biblioteca del Campus del Obelisco · ULPGC</div>
            <div class="pasaporte-lib2">El manga como recurso didáctico</div>
          </div>
        </div>
        <div class="pasaporte-titulo">${escapeHtml(_alumnoState.titulo)}</div>
        <div class="pasaporte-autor">${escapeHtml(_alumnoState.autor)}</div>
        ${reflexHtml}
        <div class="pasaporte-fecha">Explorado el ${fecha}</div>
        <div class="pasaporte-sello" aria-hidden="true">漫画</div>
        <div id="pasaporteQrSlot"></div>
      </div>
      <div class="alumno-paso-btns">
        <button type="button" class="alumno-btn alumno-btn-sec"
                data-action="printPasaporte">⎙ Imprimir pasaporte</button>
        <button type="button" class="alumno-btn alumno-btn-sec"
                data-action="_alumnoReiniciar">↺ Explorar otro título</button>
        <button type="button" class="alumno-btn alumno-btn-pri"
                data-action="closeAlumno">Finalizar</button>
      </div>
    </div>`;

  // Inyectar QR de forma asíncrona tras el render del DOM
  requestAnimationFrame(() => {
    const slot = document.getElementById('pasaporteQrSlot');
    if (slot) slot.appendChild(_generarQRSvg(_pasaporteUrl(_alumnoState.titulo), 112));
  });
}

/** Reinicia el flujo del alumno al paso 1 para explorar otro título */
function _alumnoReiniciar() {
  _alumnoState.paso = 1;
  _alumnoRender();
}

/**
 * printPasaporte — Imprime únicamente la tarjeta del pasaporte de lectura.
 *
 * Estrategia: igual que printModal() — clona #pasaporteCard, lo inyecta
 * en un div fijo que cubre todo el viewport, imprime, y limpia al terminar.
 * Esto evita que el chrome de la aplicación (nav, filtros, FABs) aparezca
 * en la salida impresa, independientemente del @media print global.
 *
 * Compatible con Chrome, Firefox, Safari y el cuadro de diálogo de impresión
 * de iOS (que ignora position:fixed en @media print).
 */
function printPasaporte() {
  const card = document.getElementById('pasaporteCard');
  if (!card) { window.print(); return; }

  // Clonar solo la tarjeta
  const clone = card.cloneNode(true);

  // Contenedor de impresión que cubre toda la pantalla
  const wrap = document.createElement('div');
  wrap.id = '__pasaporte_print__';
  wrap.setAttribute('role', 'region');
  wrap.setAttribute('aria-label', 'Pasaporte de lectura — versión imprimible');
  wrap.appendChild(clone);
  document.body.appendChild(wrap);

  // CSS de impresión inyectado dinámicamente
  const style = document.createElement('style');
  style.id = '__pasaporte_print_style__';
  style.textContent = `
    @media screen {
      #__pasaporte_print__ {
        position: fixed; inset: 0; background: #fff;
        z-index: 999999; display: flex;
        align-items: flex-start; justify-content: center;
        padding: 2rem; box-sizing: border-box; overflow: auto;
      }
      #__pasaporte_print__ .pasaporte-card {
        max-width: 360px; width: 100%; margin: auto;
      }
    }
    @media print {
      body > *:not(#__pasaporte_print__) { display: none !important; }
      #__pasaporte_print__ {
        position: static !important; padding: 0 !important;
        display: block !important; overflow: visible !important;
      }
      #__pasaporte_print__ .pasaporte-card {
        border-color: #8a6020 !important;
        box-shadow: none !important;
        break-inside: avoid;
        max-width: 100% !important;
      }
    }
  `;
  document.head.appendChild(style);

  const origOverflow = document.body.style.overflow;
  document.body.style.overflow = 'hidden';

  function cleanup() {
    if (document.body.contains(wrap))  document.body.removeChild(wrap);
    if (document.head.contains(style)) document.head.removeChild(style);
    document.body.style.overflow = origOverflow;
    window.removeEventListener('afterprint', cleanup);
  }
  window.addEventListener('afterprint', cleanup);

  // Doble rAF: garantiza que el DOM esté pintado antes de invocar print()
  requestAnimationFrame(() => requestAnimationFrame(() => window.print()));
}

// ── FAB button hook ───────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', function() {
  // Añadir botón modo alumno al FAB si no existe aún
  const fabItems = document.getElementById('fabItems');
  if (fabItems && !document.getElementById('alumnoFabBtn')) {
    const item = document.createElement('div');
    item.className = 'fab-item';
    item.innerHTML = `
      <span class="fab-label">Modo alumno</span>
      <button type="button" id="alumnoFabBtn" class="fab-action"
              onclick="openAlumno()"
              aria-label="Modo alumno guiado"
              title="Modo alumno — recorrido guiado de 4 pasos">👤</button>`;
    // Insert before the toggle button
    const toggle = document.getElementById('tools-fab-toggle');
    if (toggle && toggle.parentNode === fabItems) fabItems.insertBefore(item, toggle);
    else fabItems.appendChild(item);
  }
});


// ══════════════════════════════════════════════════════════════════
// M14 — EXPORTAR FICHA DE LECTURA COMO HTML IMPRIMIBLE
//
// Genera un archivo HTML autocontenido con la ficha de lectura guiada
// del título activo, incluyendo todas las fases expandidas.
// El docente lo abre en el navegador y usa Archivo → Imprimir → PDF.
// Sin dependencias de bibliotecas externas.
// ══════════════════════════════════════════════════════════════════

/**
 * Exporta la ficha de lectura activa como archivo HTML descargable.
 * Compatible con todos los navegadores modernos.
 */
window.exportLecturaHTML = function() {
  const titleEl   = document.getElementById('lecturaTitleEl');
  const authorEl  = document.getElementById('lecturaAuthorEl');
  const contentEl = document.getElementById('lecturaContent');
  if (!contentEl) return;

  const titulo = titleEl?.textContent?.trim() || 'Ficha de lectura';
  const autor  = authorEl?.textContent?.trim() || '';
  const now    = new Date().toLocaleDateString('es-ES', { year:'numeric', month:'long', day:'numeric' });

  // Expand all <details> for print
  const allDetails = contentEl.querySelectorAll('details');
  allDetails.forEach(d => d.setAttribute('open', ''));

  const bodyHtml = contentEl.innerHTML;

  // Restore (they were open already in the guiada spec)
  allDetails.forEach(d => d.setAttribute('open', ''));

  const html = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <title>Ficha de lectura — ${titulo}</title>
  <style>
    * { box-sizing: border-box; }
    body {
      font-family: 'Georgia', serif;
      max-width: 760px;
      margin: 0 auto;
      padding: 2rem 1.5rem;
      color: #1a1008;
      font-size: 14px;
      line-height: 1.7;
    }
    h1 { font-size: 1.3rem; margin: 0 0 .2rem; font-family: 'Georgia', serif; }
    .meta { font-size: .82rem; color: #666; margin-bottom: 1.2rem; }
    .header { border-bottom: 3px solid #B8860B; padding-bottom: .8rem; margin-bottom: 1.2rem; }
    .lectura-lomloe { display: flex; flex-wrap: wrap; gap: .3rem; margin-bottom: .8rem; }
    .lectura-comp-badge {
      display: inline-block; padding: 2px 8px; border-radius: 3px;
      font-size: .7rem; font-weight: 700; letter-spacing: .06em;
      background: rgba(42,58,122,.15); color: #1a2050;
      border: 1px solid rgba(42,58,122,.3);
    }
    details { border: 1px solid rgba(0,0,0,.12); border-radius: 5px; margin-bottom: .6rem; }
    details[open] { border-color: rgba(0,0,0,.18); }
    summary {
      padding: .55rem .8rem; cursor: default; font-weight: 700; font-size: .82rem;
      list-style: none; display: flex; align-items: baseline; gap: .4rem;
    }
    summary::-webkit-details-marker { display: none; }
    ol.lectura-qs { padding: .6rem 1rem .6rem 2rem; margin: 0; }
    ol.lectura-qs li { margin-bottom: .5rem; font-size: .88rem; }
    .lectura-visual-box { padding: .6rem 1rem; font-size: .88rem; border-top: 1px solid rgba(0,0,0,.06); }
    .fase-antes   summary { background: rgba(180,120,0,.08); }
    .fase-durante summary { background: rgba(42,90,139,.08); }
    .fase-despues summary { background: rgba(42,120,80,.08); }
    .fase-visual  summary { background: rgba(90,42,139,.08); }
    .lectura-nota-docente {
      margin-top: .8rem; border-radius: 4px;
      border: 1px dashed rgba(184,134,11,.4); background: rgba(255,252,235,.6);
    }
    .lectura-nota-hd { padding: .45rem .8rem; font-size: .75rem; font-weight: 700; }
    .lectura-nota-body { padding: .4rem 1rem .6rem; font-size: .82rem; font-style: italic; }
    .footer { margin-top: 2rem; padding-top: .6rem; border-top: 1px solid rgba(0,0,0,.1);
              font-size: .72rem; color: #888; }
    @media print {
      body { padding: 0; }
      details { page-break-inside: avoid; }
    }
  </style>
</head>
<body>
  <div class="header">
    <h1>${titulo}</h1>
    <div class="meta">${autor ? autor + ' · ' : ''}Ficha de lectura guiada</div>
    <div class="meta">Biblioteca del Campus del Obelisco · ULPGC · ${now}</div>
  </div>
  ${bodyHtml}
  <div class="footer">
    Recurso generado con <em>El manga como recurso didáctico</em> · Biblioteca Campus del Obelisco · ULPGC ·
    Para imprimir como PDF: Archivo → Imprimir → Guardar como PDF
  </div>
</body>
</html>`;

  const blob = new Blob([html], { type: 'text/html;charset=utf-8' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href     = url;
  a.download = `ficha-lectura-${titulo.replace(/[^a-z0-9]/gi, '-').toLowerCase().slice(0,40)}.html`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

// ══════════════════════════════════════════════════════════════════
// M17 — TÍTULOS SIMILARES EN LA FICHA DE AULA
//
// Cuando se abre cualquier ficha de aula, se inyectan 3 títulos
// del catálogo con el mismo uso pedagógico y nivel.
// Sin datos adicionales: usa CATALOGO + campos existentes.
// ══════════════════════════════════════════════════════════════════

/**
 * Calcula los 3 títulos más similares por uso + nivel.
 * @param {Object} entry - Entrada de CATALOGO del título activo
 * @returns {Object[]} - Hasta 3 títulos similares
 */
function _getSimilares(entry) {
  if (!entry || typeof CATALOGO === 'undefined') return [];
  const uso   = (entry.uso   || '').split(' ')[0];
  const nivel = (entry.nivel || '').split(' ')[0];

  return CATALOGO
    .filter(t =>
      t.titulo !== entry.titulo &&
      t.uso && t.uso.includes(uso) &&
      t.nivel && t.nivel.includes(nivel) &&
      t.tip    // Solo títulos con descripción pedagógica
    )
    .sort(() => Math.random() - 0.5)  // Rotación aleatoria para variedad
    .slice(0, 3);
}

/**
 * Inyecta el panel de similares en el modal de ficha de aula.
 * Se llama desde openFicha / openLectura después de renderizar el contenido.
 * @param {string} tituloActivo - Título del manga activo
 */
function renderSimilares(tituloActivo) {
  // Solo inyectar en la ficha de aula (fichaModal), no en lecturaModal
  const target = document.getElementById('fichaBody') || document.getElementById('fichaContent');
  if (!target) return;

  // Evitar duplicados
  target.querySelectorAll('.similares-panel').forEach(el => el.remove());

  const entry = (typeof CATALOGO !== 'undefined')
    ? CATALOGO.find(t => t.titulo === tituloActivo)
    : null;
  if (!entry) return;

  const similares = _getSimilares(entry);
  if (!similares.length) return;

  const panel = document.createElement('div');
  panel.className = 'similares-panel';
  panel.setAttribute('aria-label', 'Títulos similares del fondo');
  panel.innerHTML = `
    <h4 class="similares-title">También en el fondo</h4>
    <div class="similares-grid">
      ${similares.map(t => `
        <button type="button"
                class="similares-card"
                style="border-left-color:#${(t.color||'#5a3a1a').replace('#','')}"
                data-titulo="${(t.titulo||'').replace(/"/g,'&quot;')}"
                data-autor="${(t.autor||'').replace(/"/g,'&quot;')}"
                data-tip="${(t.tip||'').slice(0,200).replace(/"/g,'&quot;')}"
                data-uso="${t.uso||''}"
                data-nivel="${t.nivel||''}"
                aria-label="Abrir ficha de ${t.titulo}">
          <span class="sim-uso" style="background:${t.color||'#5a3a1a'}">${t.badges?.[0]||t.uso}</span>
          <span class="sim-titulo">${t.titulo}</span>
          <span class="sim-autor">${(t.autor||'').split('·')[0].trim()}</span>
          <span class="sim-tip">${(t.tip||'').slice(0,80)}…</span>
        </button>`).join('')}
    </div>`;

  // Click: open lectura for the similar title
  panel.querySelectorAll('.similares-card').forEach(btn => {
    btn.addEventListener('click', () => {
      const vCard = _makeVirtualCard(
        btn.dataset.titulo,
        btn.dataset.autor,
        btn.dataset.tip,
        btn.dataset.uso,
        btn.dataset.nivel
      );
      openLectura(vCard);
    });
  });

  target.appendChild(panel);
}

// Hook into openLectura to inject similares
(function _patchOpenLecturaForSimilares() {
  const _origOpen = window.openLectura;
  window.openLectura = function(card) {
    _origOpen.call(this, card);
    const titulo = card?.querySelector?.('.cat-title')?.textContent?.trim()
                || card?.dataset?.titulo || '';
    setTimeout(() => renderSimilares(titulo), 80);
  };
})();

// ══════════════════════════════════════════════════════════════════
// M18 — RANKING DE TÍTULOS MÁS CONSULTADOS EN SESIÓN
//
// Reutiliza sessionLog (ya existente) para construir un top-10 de
// títulos más abiertos durante la sesión activa.
// Panel accesible desde el FAB con el botón 📊.
// ══════════════════════════════════════════════════════════════════

/** Abre el panel de ranking de sesión. */
window.openRanking = function() {
  let panel = document.getElementById('rankingPanel');
  if (!panel) {
    panel = document.createElement('div');
    panel.id        = 'rankingPanel';
    panel.className = 'ranking-panel';
    panel.setAttribute('role', 'dialog');
    panel.setAttribute('aria-modal', 'true');
    panel.setAttribute('aria-labelledby', 'rankingTitle');
    panel.innerHTML = `
      <div class="ranking-header">
        <h2 id="rankingTitle" class="ranking-title">📊 Títulos más consultados hoy</h2>
        <button type="button" class="ranking-close" onclick="closeRanking()" aria-label="Cerrar ranking">✕</button>
      </div>
      <div id="rankingBody" class="ranking-body"></div>
      <p class="ranking-footer">Datos de esta sesión · Se resetean al cerrar el navegador</p>`;
    document.body.appendChild(panel);
    panel.addEventListener('click', e => { if (e.target === panel) closeRanking(); });
  }
  _renderRanking();
  panel.classList.add('open');
  document.body.style.overflow = 'hidden';
};

window.closeRanking = function() {
  document.getElementById('rankingPanel')?.classList.remove('open');
  document.body.style.overflow = '';
};

function _renderRanking() {
  const body = document.getElementById('rankingBody');
  if (!body) return;

  // Build counts from sessionLog (existing system)
  const counts = {};
  if (typeof sessionLog !== 'undefined') {
    Object.values(sessionLog).forEach(arr => {
      arr.forEach(entry => {
        if (entry.title) counts[entry.title] = (counts[entry.title] || 0) + 1;
      });
    });
  }

  const entries = Object.entries(counts)
    .sort(([,a],[,b]) => b - a)
    .slice(0, 10);

  if (!entries.length) {
    body.innerHTML = '<p class="ranking-empty">Aún no se ha consultado ningún título en esta sesión.</p>';
    return;
  }

  const maxVal = entries[0][1];
  body.innerHTML = entries.map(([title, count], i) => {
    const pct    = Math.round((count / maxVal) * 100);
    const cat    = (typeof CATALOGO !== 'undefined') ? CATALOGO.find(t => t.titulo === title) : null;
    const color  = cat?.color || '#5a3a1a';
    const badge  = cat?.badges?.[0] || '';
    return `
      <div class="ranking-row" data-rank="${i+1}">
        <span class="ranking-num">${i+1}</span>
        <div class="ranking-info">
          <span class="ranking-titulo">${title}</span>
          ${badge ? `<span class="ranking-badge" style="background:${color}">${badge}</span>` : ''}
          <div class="ranking-bar-wrap">
            <div class="ranking-bar" style="width:${pct}%;background:${color}"></div>
          </div>
        </div>
        <span class="ranking-count">${count}</span>
      </div>`;
  }).join('');
}

// Inject ranking FAB button on DOMContentLoaded
document.addEventListener('DOMContentLoaded', function() {
  const fabItems = document.getElementById('fabItems');
  if (fabItems && !document.getElementById('rankingFabBtn')) {
    const item = document.createElement('div');
    item.className = 'fab-item';
    item.innerHTML = `
      <span class="fab-label">Títulos consultados</span>
      <button type="button" id="rankingFabBtn" class="fab-action"
              onclick="openRanking()"
              aria-label="Ver ranking de títulos más consultados"
              title="Ranking de sesión">📊</button>`;
    const toggle = document.getElementById('tools-fab-toggle');
    if (toggle && toggle.parentNode === fabItems) fabItems.insertBefore(item, toggle);
    else fabItems.appendChild(item);
  }
});


// ══════════════════════════════════════════════════════════════════
// M20 — TEST DE VOCABULARIO JAPONÉS
//
// Juego de 4 fases: escucha la pronunciación → elige la romanización.
// Reutiliza GLOSARIO_PRONUNCIACIONES y SpeechSynthesis (M7).
// Sin datos adicionales. Compatible con el mismo fallback de M7.
// ══════════════════════════════════════════════════════════════════

let _vocabState = null;

/** Abre el test de vocabulario. */
window.openVocabTest = function() {
  if (!('speechSynthesis' in window)) {
    alert('Este test requiere síntesis de voz. Tu navegador no la admite.');
    return;
  }
  let modal = document.getElementById('vocabModal');
  if (!modal) {
    const overlay = document.createElement('div');
    overlay.id        = 'vocabOverlay';
    overlay.className = 'vocab-overlay';
    overlay.setAttribute('role', 'dialog');
    overlay.setAttribute('aria-modal', 'true');
    overlay.setAttribute('aria-labelledby', 'vocabTitle');
    overlay.innerHTML = `
      <div id="vocabModal" class="vocab-modal">
        <div class="vocab-header">
          <h2 id="vocabTitle" class="vocab-title">🎧 Test de vocabulario japonés</h2>
          <button type="button" class="vocab-close" onclick="closeVocabTest()" aria-label="Cerrar test">✕</button>
        </div>
        <div id="vocabBody" class="vocab-body"></div>
      </div>`;
    document.body.appendChild(overlay);
    overlay.addEventListener('click', e => { if (e.target === overlay) closeVocabTest(); });
    modal = overlay;
  }
  _vocabStart();
  modal.classList.add('open');
  document.body.style.overflow = 'hidden';
};

window.closeVocabTest = function() {
  document.getElementById('vocabOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
  window.speechSynthesis?.cancel();
  _vocabState = null;
};

function _vocabStart() {
  // Shuffle and pick 8 questions
  const pool = [...GLOSARIO_PRONUNCIACIONES]
    .sort(() => Math.random() - 0.5)
    .slice(0, 8);

  _vocabState = { questions: pool, current: 0, score: 0, answered: false };
  _vocabRender();
}

function _vocabRender() {
  const body = document.getElementById('vocabBody');
  if (!body || !_vocabState) return;

  const { questions, current, score } = _vocabState;

  if (current >= questions.length) {
    _vocabShowResult(body, score, questions.length);
    return;
  }

  const q = questions[current];

  // Build 4 options: correct + 3 random wrong
  const wrong = GLOSARIO_PRONUNCIACIONES
    .filter(g => g.id !== q.id)
    .sort(() => Math.random() - 0.5)
    .slice(0, 3);
  const options = [...wrong, q].sort(() => Math.random() - 0.5);

  body.innerHTML = `
    <div class="vocab-progress">
      <div class="vocab-progress-bar" style="width:${(current/questions.length)*100}%"></div>
    </div>
    <div class="vocab-question">
      <p class="vocab-instruction">¿Cuál es la romanización de este término?</p>
      <button type="button" class="vocab-play-btn" id="vocabPlayBtn"
              onclick="_vocabPlay('${q.japanese.replace(/'/g,"\\'")}','${q.romaji.replace(/'/g,"\\'")}',this)"
              aria-label="Escuchar pronunciación de ${q.label}">
        🔊 Escuchar
      </button>
      <div class="vocab-kanji" lang="ja" aria-label="Kanji del término">${q.japanese}</div>
      <p class="vocab-label-hint">${q.label}</p>
    </div>
    <div class="vocab-options" id="vocabOptions">
      ${options.map((opt,i) => `
        <button type="button"
                class="vocab-opt-btn"
                id="vocabOpt${i}"
                onclick="_vocabAnswer('${opt.id}','${q.id}',${i})"
                aria-label="Opción: ${opt.romaji}">
          ${opt.romaji}
        </button>`).join('')}
    </div>
    <div class="vocab-feedback" id="vocabFeedback" aria-live="assertive"></div>
    <div class="vocab-score">Pregunta ${current+1} de ${questions.length} · Puntos: ${score}</div>`;

  // Auto-play on first render
  setTimeout(() => {
    _vocabPlay(q.japanese, q.romaji, document.getElementById('vocabPlayBtn'));
  }, 300);
}

function _vocabPlay(japanese, romaji, btn) {
  if (!('speechSynthesis' in window)) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance();
  if (_japaneseVoice) {
    utterance.voice = _japaneseVoice;
    utterance.lang  = 'ja-JP';
    utterance.text  = japanese;
  } else {
    utterance.lang = 'es-ES';
    utterance.text = romaji;
  }
  utterance.rate = 0.8;
  if (btn) { btn.textContent = '🔊 …'; btn.disabled = true; }
  utterance.onend = () => {
    if (btn) { btn.textContent = '🔊 Escuchar de nuevo'; btn.disabled = false; }
  };
  window.speechSynthesis.speak(utterance);
}

function _vocabAnswer(selectedId, correctId, btnIdx) {
  if (_vocabState.answered) return;
  _vocabState.answered = true;

  const correct = selectedId === correctId;
  if (correct) _vocabState.score++;

  const correctEntry = GLOSARIO_PRONUNCIACIONES.find(g => g.id === correctId);

  // Highlight buttons
  document.querySelectorAll('.vocab-opt-btn').forEach((btn, i) => {
    btn.disabled = true;
    if (btn.id === `vocabOpt${btnIdx}`) {
      btn.classList.add(correct ? 'vocab-correct' : 'vocab-wrong');
    }
    // Always reveal correct
    const optId = btn.onclick?.toString().match(/'([^']+)'/)?.[1];
    if (optId === correctId) btn.classList.add('vocab-correct');
  });

  const feedback = document.getElementById('vocabFeedback');
  if (feedback) {
    feedback.className = 'vocab-feedback ' + (correct ? 'vocab-feedback-ok' : 'vocab-feedback-err');
    feedback.innerHTML = correct
      ? `✓ ¡Correcto! <strong>${correctEntry?.romaji}</strong> — ${correctEntry?.label}`
      : `✗ Era <strong>${correctEntry?.romaji}</strong> — ${correctEntry?.label}`;
  }

  setTimeout(() => {
    _vocabState.current++;
    _vocabState.answered = false;
    _vocabRender();
  }, 1800);
}

function _vocabShowResult(body, score, total) {
  const pct  = Math.round((score/total)*100);
  const msg  = pct >= 80 ? '¡Excelente dominio del vocabulario!' :
               pct >= 50 ? 'Buen progreso. ¡Sigue practicando!' :
               'Sigue escuchando los términos en el glosario.';
  body.innerHTML = `
    <div class="vocab-result">
      <div class="vocab-result-score">${score}/${total}</div>
      <div class="vocab-result-pct">${pct}%</div>
      <p class="vocab-result-msg">${msg}</p>
      <div class="vocab-result-btns">
        <button type="button" class="vocab-btn-pri" onclick="_vocabStart()">▶ Repetir test</button>
        <button type="button" class="vocab-btn-sec" onclick="closeVocabTest()">Cerrar</button>
      </div>
    </div>`;
}

// Add vocab test button to glosario header after initGlosarioPronunciador runs
document.addEventListener('DOMContentLoaded', function() {
  setTimeout(() => {
    const tourBtn = document.getElementById('gloss-tour-btn');
    if (tourBtn && !document.getElementById('gloss-vocab-btn')) {
      const vocabBtn = document.createElement('button');
      vocabBtn.type      = 'button';
      vocabBtn.id        = 'gloss-vocab-btn';
      vocabBtn.className = 'gloss-tour-btn';
      vocabBtn.textContent = '🎧 Test de vocabulario';
      vocabBtn.title     = 'Pon a prueba tu memoria auditiva: escucha y elige la romanización correcta';
      vocabBtn.addEventListener('click', openVocabTest);
      tourBtn.insertAdjacentElement('afterend', vocabBtn);
    }
  }, 500);
});
